{
  "name": "American Cultural Insider",
  "description": "An interactive language coach to help you master casual, natural American English. Learn slang, idioms, and pronunciation through guided practice and AI feedback.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { AppPhase, Level, VibeCheckContent } from './types';
import Welcome from './components/Welcome';
import PhaseOne from './components/PhaseOne';
import PhaseTwo from './components/PhaseTwo';
import PhaseThree from './components/PhaseThree';

const App: React.FC = () => {
  const [phase, setPhase] = useState<AppPhase>(AppPhase.WELCOME);
  const [level, setLevel] = useState<Level>(Level.TOURIST);
  const [showReference, setShowReference] = useState<string>('');

  const [socialScript, setSocialScript] = useState<string>('');
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioAnalysis, setAudioAnalysis] = useState<string>('');
  const [vibeCheck, setVibeCheck] = useState<VibeCheckContent | null>(null);

  const handleStart = useCallback((selectedLevel: Level, reference: string) => {
    setLevel(selectedLevel);
    setShowReference(reference);
    setPhase(AppPhase.PHASE_1_GENERATE);
  }, []);

  const handleScriptGenerated = useCallback((script: string) => {
    setSocialScript(script);
    setPhase(AppPhase.PHASE_1_RECORD);
  }, []);

  const handleRecordingComplete = useCallback((blob: Blob) => {
    setAudioBlob(blob);
    setPhase(AppPhase.PHASE_2_ANALYZE);
  }, []);

  const handleAnalysisComplete = useCallback((analysis: string) => {
    setAudioAnalysis(analysis);
    setPhase(AppPhase.PHASE_2_REVIEW);
  }, []);

  const handleContinueToVibeCheck = useCallback(() => {
    setPhase(AppPhase.PHASE_3_GENERATE);
  }, []);

  const handleVibeCheckGenerated = useCallback((vibeCheckContent: VibeCheckContent) => {
    setVibeCheck(vibeCheckContent);
    setPhase(AppPhase.PHASE_3_PRACTICE);
  }, []);

  const handleNextScript = useCallback(() => {
    // Reset state for the next round, but keep level and reference
    setSocialScript('');
    setAudioBlob(null);
    setAudioAnalysis('');
    setVibeCheck(null);
    setPhase(AppPhase.PHASE_1_GENERATE);
  }, []);

  const renderContent = () => {
    switch (phase) {
      case AppPhase.WELCOME:
        return <Welcome onStart={handleStart} />;
      case AppPhase.PHASE_1_GENERATE:
      case AppPhase.PHASE_1_RECORD:
        return (
          <PhaseOne 
            level={level}
            showReference={showReference}
            currentPhase={phase}
            onScriptGenerated={handleScriptGenerated}
            onRecordingComplete={handleRecordingComplete}
            socialScript={socialScript}
          />
        );
      case AppPhase.PHASE_2_ANALYZE:
      case AppPhase.PHASE_2_REVIEW:
        return (
          <PhaseTwo
            currentPhase={phase}
            script={socialScript}
            audioBlob={audioBlob}
            onAnalysisComplete={handleAnalysisComplete}
            analysisResult={audioAnalysis}
            onContinue={handleContinueToVibeCheck}
          />
        );
      case AppPhase.PHASE_3_GENERATE:
      case AppPhase.PHASE_3_PRACTICE:
         return (
          <PhaseThree
            currentPhase={phase}
            script={socialScript}
            onVibeCheckGenerated={handleVibeCheckGenerated}
            vibeCheckContent={vibeCheck}
            onNextScript={handleNextScript}
          />
         );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center justify-center p-4 selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-indigo-400 tracking-tight">
            The American Cultural Insider
          </h1>
          <p className="text-gray-400 mt-2">Your coach for sounding like a local 🤙</p>
        </header>
        <main className="bg-gray-800 rounded-2xl shadow-2xl p-6 md:p-8 min-h-[400px] flex flex-col justify-center">
          {renderContent()}
        </main>
         <footer className="text-center mt-8 text-gray-500 text-sm">
            <p>Powered by Gemini. Built for a natural, authentic learning experience.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

export enum AppPhase {
  WELCOME = 'WELCOME',
  PHASE_1_GENERATE = 'PHASE_1_GENERATE',
  PHASE_1_RECORD = 'PHASE_1_RECORD',
  PHASE_2_ANALYZE = 'PHASE_2_ANALYZE',
  PHASE_2_REVIEW = 'PHASE_2_REVIEW',
  PHASE_3_GENERATE = 'PHASE_3_GENERATE',
  PHASE_3_PRACTICE = 'PHASE_3_PRACTICE',
}

export enum Level {
  TOURIST = 'The Tourist',
  LOCAL = 'The Local',
  INSIDER = 'The Insider',
}

export interface VibeCheckContent {
  questions: string[];
  challenge: string;
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const generateSocialScript = async (level: Level, showReference: string): Promise<string> => {
    const ai = getAi();
    const scriptType = ["dialogue script", "social media post", "story time narrative"][Math.floor(Math.random() * 3)];

    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. Use emojis occasionally.";
    const prompt = `Generate a short, casual text (100-150 words) for a language learner at '${level}' level. The text should be a ${scriptType} and include heavy natural elements like phrasal verbs, slang, and contractions appropriate for that level. ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob): Promise<string> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your goal is to help a user sound more like a native American English speaker by analyzing their audio recording of a script. Focus on connected speech, flap-t sounds, intonation, and rhythm. Prioritize flow over perfect grammar. Be encouraging and use a 'How it looks' vs 'How it sounds' format for your examples. Format your response using markdown.";
    const contents = {
        parts: [
            { text: `Here is the script the user was reading: "${script}"` },
            audioPart,
            { text: `Now, analyze the user's audio. Provide specific, markdown-formatted feedback on their pronunciation, focusing on 2-3 key areas for improvement. Use the "How it looks" vs "How it sounds" format for your examples (e.g., "How it looks: 'going to', How it sounds: 'gonna'"). Keep the feedback concise, actionable, and encouraging.` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction: systemInstruction,
            }
        });
        return response.text || "Could not analyze the audio. The AI might not have been able to process it.";
    } catch (error) {
        console.error("Error analyzing audio:", error);
        return "There was an issue analyzing your audio. Please try recording again.";
    }
};

export const generateVibeCheck = async (script: string): Promise<VibeCheckContent> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider.' Your goal is to test a user's comprehension of nuance and slang from a text they just read.";
    const prompt = `Based on this text: "${script}", generate a JSON object. This object must have a 'questions' key with an array of two strings, each a question about the underlying meaning or nuance (e.g., sarcasm, word choice). It must also have a 'challenge' key with a string prompting the user to use a specific slang word or phrasal verb from the text in a sentence about their own life.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        questions: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        },
                        challenge: {
                            type: Type.STRING
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as VibeCheckContent;
    } catch (error) {
        console.error("Error generating vibe check:", error);
        return {
            questions: ["Could not generate a question. What do you think the main feeling of the text was?", "What's one word you learned?"],
            challenge: "Try using a word from the text in a sentence!"
        };
    }
};

import React, { useState, useMemo } from 'react';
import { Level } from '../types';
import { Button } from './ui/Button';

interface WelcomeProps {
  onStart: (level: Level, reference: string) => void;
}

const Welcome: React.FC<WelcomeProps> = ({ onStart }) => {
  const [levelValue, setLevelValue] = useState(5);
  const [reference, setReference] = useState('');

  const derivedLevel = useMemo(() => {
    if (levelValue <= 3) return Level.TOURIST;
    if (levelValue <= 7) return Level.LOCAL;
    return Level.INSIDER;
  }, [levelValue]);

  const levelDescription = useMemo(() => {
    switch(derivedLevel) {
      case Level.TOURIST:
        return "You'll master basic contractions (gonna, wanna) and common idioms. Perfect for clear, friendly conversations.";
      case Level.LOCAL:
        return "We'll dive into phrasal verbs and filler words (like, you know) to make you sound super natural.";
      case Level.INSIDER:
        return "Get ready for the latest slang, regional flavor, and nuanced sarcasm. You'll sound like you grew up here.";
    }
  }, [derivedLevel]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onStart(derivedLevel, reference);
  };

  return (
    <div className="text-center animate-fade-in">
      <h2 className="text-2xl font-bold text-white mb-2">Ready to sound like a local?</h2>
      <p className="text-gray-400 mb-6">Let's kick things off. First, tell me your goals.</p>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div>
          <label htmlFor="level-slider" className="block text-lg font-medium text-gray-200 mb-3">
            On a scale of 1-10, how 'American' do you wanna sound?
          </label>
          <input
            id="level-slider"
            type="range"
            min="1"
            max="10"
            value={levelValue}
            onChange={(e) => setLevelValue(parseInt(e.target.value, 10))}
            className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"
          />
          <div className="flex justify-between text-xs text-gray-400 px-1 mt-2">
            <span>Textbook</span>
            <span>Native</span>
          </div>
          <div className="mt-4 text-center p-4 bg-gray-700/50 rounded-lg">
            <p className="font-bold text-indigo-400 text-lg">{derivedLevel}</p>
            <p className="text-gray-300 text-sm">{levelDescription}</p>
          </div>
        </div>

        <div>
          <label htmlFor="reference" className="block text-lg font-medium text-gray-200 mb-3">
            Any movies or shows where you like the way people talk? (Optional)
          </label>
          <input
            id="reference"
            type="text"
            value={reference}
            onChange={(e) => setReference(e.target.value)}
            placeholder="e.g., 'Friends', 'The Office', a YouTuber..."
            className="w-full bg-gray-700 border border-gray-600 rounded-md px-4 py-2 text-white placeholder-gray-400 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
          />
        </div>

        <Button type="submit">Let's Go! 🚀</Button>
      </form>
    </div>
  );
};

export default Welcome;

import React, { useEffect, useState } from 'react';
import { generateSocialScript } from '../services/geminiService';
import { AppPhase, Level } from '../types';
import { Spinner } from './ui/Spinner';
import { Recorder } from './ui/Recorder';

interface PhaseOneProps {
  level: Level;
  showReference: string;
  currentPhase: AppPhase;
  onScriptGenerated: (script: string) => void;
  onRecordingComplete: (blob: Blob) => void;
  socialScript: string;
}

const PhaseOne: React.FC<PhaseOneProps> = ({ level, showReference, currentPhase, onScriptGenerated, onRecordingComplete, socialScript }) => {
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (currentPhase === AppPhase.PHASE_1_GENERATE) {
      const fetchScript = async () => {
        try {
          const script = await generateSocialScript(level, showReference);
          onScriptGenerated(script);
        } catch (e) {
          setError('Failed to generate script. Please try again.');
          console.error(e);
        }
      };
      fetchScript();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPhase]);

  if (currentPhase === AppPhase.PHASE_1_GENERATE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Cooking up a fresh script for you...</p>
      </div>
    );
  }

  if (error) {
    return <p className="text-red-400 text-center">{error}</p>;
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6">
      <h2 className="text-xl font-bold text-indigo-400">Phase 1: The Social Script</h2>
      <div className="w-full p-4 bg-gray-700/50 rounded-lg max-h-60 overflow-y-auto">
        <p className="text-gray-200 whitespace-pre-wrap leading-relaxed">{socialScript}</p>
      </div>
      <p className="text-center text-gray-300">
        Record yourself reading this out loud. Try to mimic a natural, relaxed American rhythm.
      </p>
      <Recorder onRecordingComplete={onRecordingComplete} />
    </div>
  );
};

export default PhaseOne;

import React, { useEffect, useState } from 'react';
import { analyzeAudio } from '../services/geminiService';
import { AppPhase } from '../types';
import { Spinner } from './ui/Spinner';
import { Button } from './ui/Button';

interface PhaseTwoProps {
  currentPhase: AppPhase;
  script: string;
  audioBlob: Blob | null;
  onAnalysisComplete: (analysis: string) => void;
  analysisResult: string;
  onContinue: () => void;
}

const PhaseTwo: React.FC<PhaseTwoProps> = ({ currentPhase, script, audioBlob, onAnalysisComplete, analysisResult, onContinue }) => {
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (currentPhase === AppPhase.PHASE_2_ANALYZE && audioBlob) {
      const getAnalysis = async () => {
        try {
          const analysis = await analyzeAudio(script, audioBlob);
          onAnalysisComplete(analysis);
        } catch (e) {
          setError('Failed to analyze audio. Please try again.');
          console.error(e);
        }
      };
      getAnalysis();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPhase, audioBlob]);

  if (currentPhase === AppPhase.PHASE_2_ANALYZE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Listening closely... Our AI coach is analyzing your recording.</p>
      </div>
    );
  }

  if (error) {
    return <p className="text-red-400 text-center">{error}</p>;
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6">
      <h2 className="text-xl font-bold text-indigo-400">Phase 2: Ear-Training Analysis</h2>
      <div className="w-full p-4 bg-gray-700/50 rounded-lg max-h-80 overflow-y-auto prose prose-invert prose-p:text-gray-300 prose-headings:text-indigo-400 prose-strong:text-white">
        <div dangerouslySetInnerHTML={{ __html: analysisResult.replace(/\n/g, '<br />') }} />
      </div>
      <Button onClick={onContinue}>
        Got it, Continue
      </Button>
    </div>
  );
};

export default PhaseTwo;

import React, { useEffect, useState } from 'react';
import { generateVibeCheck } from '../services/geminiService';
import { AppPhase, VibeCheckContent } from '../types';
import { Spinner } from './ui/Spinner';
import { Button } from './ui/Button';

interface PhaseThreeProps {
  currentPhase: AppPhase;
  script: string;
  onVibeCheckGenerated: (vibeCheck: VibeCheckContent) => void;
  vibeCheckContent: VibeCheckContent | null;
  onNextScript: () => void;
}

const PhaseThree: React.FC<PhaseThreeProps> = ({ currentPhase, script, onVibeCheckGenerated, vibeCheckContent, onNextScript }) => {
  const [error, setError] = useState<string | null>(null);
  const [answers, setAnswers] = useState<string[]>(['', '', '']);

  useEffect(() => {
    if (currentPhase === AppPhase.PHASE_3_GENERATE) {
      const getVibeCheck = async () => {
        try {
          const content = await generateVibeCheck(script);
          onVibeCheckGenerated(content);
        } catch (e) {
          setError('Failed to generate vibe check. Please try again.');
          console.error(e);
        }
      };
      getVibeCheck();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPhase]);

  const handleAnswerChange = (index: number, value: string) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  if (currentPhase === AppPhase.PHASE_3_GENERATE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Prepping your vibe check...</p>
      </div>
    );
  }

  if (error || !vibeCheckContent) {
    return (
      <div className="text-center">
        <p className="text-red-400">{error || 'Could not load content.'}</p>
        <Button onClick={onNextScript} className="mt-4">Try a new script</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6 w-full">
      <h2 className="text-xl font-bold text-indigo-400">Phase 3: The Vibe Check</h2>
      <div className="w-full space-y-6">
        {vibeCheckContent.questions.map((q, i) => (
          <div key={i}>
            <label className="block text-gray-300 mb-2">{i + 1}. {q}</label>
            <input
              type="text"
              value={answers[i]}
              onChange={(e) => handleAnswerChange(i, e.target.value)}
              className="w-full bg-gray-700 border border-gray-600 rounded-md px-4 py-2 text-white placeholder-gray-400 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
            />
          </div>
        ))}
        <div>
          <label className="block text-gray-300 mb-2">{vibeCheckContent.questions.length + 1}. {vibeCheckContent.challenge}</label>
          <input
            type="text"
            value={answers[2]}
            onChange={(e) => handleAnswerChange(2, e.target.value)}
            className="w-full bg-gray-700 border border-gray-600 rounded-md px-4 py-2 text-white placeholder-gray-400 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
          />
        </div>
      </div>
      <Button onClick={onNextScript} className="mt-4">
        Great Job! Next Script
      </Button>
    </div>
  );
};

export default PhaseThree;

