import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Accent, Goal } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (audioBlob: Blob, goal: Goal, calibrationText: string): Promise<Level> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's proficiency and recommend a learning track. The user's stated goal is to learn to speak more '${goal}'.`;
    const prompt = `The user read the following text: "${calibrationText}". Please analyze their audio recording for proficiency (clarity, rhythm, use of connected speech, etc.). Based on their proficiency and their stated goal, place them into one of the following learning tracks: 'The Tourist' (for beginners focusing on clarity), 'The Local' (for intermediates focusing on natural flow), or 'The Insider' (for advanced learners ready for modern slang). Return a JSON object with a single key 'level' containing one of those three string values.`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: {
                            type: Type.STRING,
                            enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER]
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        const result = JSON.parse(jsonText) as { level: Level };
        return result.level || Level.TOURIST;
    } catch (error) {
        console.error("Error assessing user level:", error);
        return Level.TOURIST; // Default to beginner level on error
    }
};

export const generateSocialScript = async (level: Level, showReference: string, accent: Accent): Promise<string> => {
    const ai = getAi();
    const scriptType = ["dialogue script", "social media post", "story time narrative"][Math.floor(Math.random() * 3)];

    const accentInstruction = accent !== Accent.STANDARD 
      ? ` The script should be written with a ${accent} accent, including common phrases, slang, and speech patterns from that region.` 
      : '';

    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. You MUST NOT use emojis.";
    const prompt = `Generate a very short, casual text (maximum one paragraph and around 50-75 words) for a language learner at '${level}' level. The text should be a ${scriptType} and include heavy natural elements like phrasal verbs, slang, and contractions appropriate for that level.${accentInstruction} ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob, accent: Accent): Promise<string> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const accentInstruction = accent !== Accent.STANDARD
        ? ` The user is specifically trying to learn a ${accent} accent. Your feedback should also explain key pronunciation differences or common phrases associated with the ${accent} accent that are relevant to the script.`
        : '';

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your goal is to help a user sound more like a native American English speaker by analyzing their audio recording of a script. Focus on connected speech, flap-t sounds, intonation, and rhythm. Prioritize flow over perfect grammar. Be encouraging and use a 'How it looks' vs 'How it sounds' format for your examples. Format your response using markdown.";
    const contents = {
        parts: [
            { text: `Here is the script the user was reading: "${script}"` },
            audioPart,
            { text: `Now, analyze the user's audio. Provide specific, markdown-formatted feedback on their pronunciation, focusing on 2-3 key areas for improvement. Use the "How it looks" vs "How it sounds" format for your examples (e.g., "How it looks: 'going to', How it sounds: 'gonna'"). Keep the feedback concise, actionable, and encouraging.${accentInstruction}` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction: systemInstruction,
            }
        });
        return response.text || "Could not analyze the audio. The AI might not have been able to process it.";
    } catch (error) {
        console.error("Error analyzing audio:", error);
        return "There was an issue analyzing your audio. Please try recording again.";
    }
};

export const generateVibeCheck = async (script: string): Promise<VibeCheckContent> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider.' Your goal is to test a user's comprehension of nuance and slang from a text they just read, and to explain the slang.";
    const prompt = `Based on this text: "${script}", generate a JSON object. This object must have three keys: 'slangBreakdown', 'questions', and 'challenge'. 'slangBreakdown' must be an array of objects, where each object has a 'term' (the slang word or phrasal verb from the text) and a 'meaning' (a clear, simple explanation). 'questions' must be an array of two strings, each a question about the underlying meaning or nuance (e.g., sarcasm, word choice). 'challenge' must be a string prompting the user to use one of the slang words in a sentence about their own life.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        slangBreakdown: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    term: { type: Type.STRING },
                                    meaning: { type: Type.STRING }
                                }
                            }
                        },
                        questions: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        },
                        challenge: {
                            type: Type.STRING
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as VibeCheckContent;
    } catch (error) {
        console.error("Error generating vibe check:", error);
        return {
            slangBreakdown: [{ term: "N/A", meaning: "Could not generate slang breakdown."}],
            questions: ["Could not generate a question. What do you think the main feeling of the text was?", "What's one word you learned?"],
            challenge: "Try using a word from the text in a sentence!"
        };
    }
};

