import React, { useState, useCallback } from 'react';
import { assessUserLevel } from '../services/geminiService';
import { AppPhase, Goal, Level } from '../types';
import { Spinner } from './ui/Spinner';
import { Recorder } from './ui/Recorder';
import { Button } from './ui/Button';

interface AssessmentProps {
  currentPhase: AppPhase;
  goal: Goal;
  onAssessmentComplete: (determinedLevel: Level) => void;
}

const CALIBRATION_TEXT = "The quick brown fox jumps over the lazy dog. After that, I'm probably going to get a coffee and check out that new movie everyone's talking about.";

const Assessment: React.FC<AssessmentProps> = ({ currentPhase, goal, onAssessmentComplete }) => {
  const [error, setError] = useState<string | null>(null);

  const handleRecording = useCallback(async (audioBlob: Blob) => {
    try {
      const level = await assessUserLevel(audioBlob, goal, CALIBRATION_TEXT);
      onAssessmentComplete(level);
    } catch (e) {
      setError('Failed to assess your level. Please try again.');
      console.error(e);
    }
  }, [goal, onAssessmentComplete]);

  if (currentPhase === AppPhase.ASSESSMENT_ANALYZE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Calibrating your level... The AI is analyzing your voice.</p>
      </div>
    );
  }

  if (error) {
    return (
        <div className="text-center">
            <p className="text-red-400 text-center">{error}</p>
            <Button onClick={() => window.location.reload()} className="mt-4">Start Over</Button>
        </div>
    );
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6">
      <h2 className="text-xl font-bold text-indigo-400">Let's Calibrate Your Level</h2>
      <p className="text-center text-gray-300">
        To get started, please record yourself reading the short text below. This will help our AI coach find the perfect starting point for you.
      </p>
      <div className="w-full p-4 bg-gray-700/50 rounded-lg">
        <p className="text-gray-200 whitespace-pre-wrap leading-relaxed font-medium text-center">{CALIBRATION_TEXT}</p>
      </div>
      <Recorder onRecordingComplete={handleRecording} />
    </div>
  );
};

export default Assessment;

export enum AppPhase {
