  ASSESSMENT_RECORD = 'ASSESSMENT_RECORD',
  ASSESSMENT_ANALYZE = 'ASSESSMENT_ANALYZE',
  ASSESSMENT_RESULTS = 'ASSESSMENT_RESULTS',
  PHASE_1_GENERATE = 'PHASE_1_GENERATE',
  PHASE_1_RECORD = 'PHASE_1_RECORD',
  PHASE_2_ANALYZE = 'PHASE_2_ANALYZE',
  PHASE_2_REVIEW = 'PHASE_2_REVIEW',
  PHASE_3_GENERATE = 'PHASE_3_GENERATE',
  PHASE_3_PRACTICE = 'PHASE_3_PRACTICE',
}

export enum Level {
  TOURIST = 'The Tourist',
  LOCAL = 'The Local',
  INSIDER = 'The Insider',
}

export enum Goal {
  CASUAL = 'Natural & Clear',
  SLANG = 'Fluent with Slang',
}

export interface SlangTerm {
  term: string;
  meaning: string;
}

export interface VibeCheckContent {
  slangBreakdown: SlangTerm[];
  questions: string[];
  challenge: string;
}

export interface AssessmentResult {
  level: Level;
  levelNumber: number;
  feedback: string;
  plan: string;
}

import React, { useState, useCallback } from 'react';
import { AppPhase, Level, VibeCheckContent, Goal, AssessmentResult } from './types';
import Welcome from './components/Welcome';
import Assessment from './components/Assessment';
import AssessmentResults from './components/AssessmentResults';
import PhaseOne from './components/PhaseOne';
import PhaseTwo from './components/PhaseTwo';
import PhaseThree from './components/PhaseThree';

const App: React.FC = () => {
  const [phase, setPhase] = useState<AppPhase>(AppPhase.WELCOME);
  const [level, setLevel] = useState<Level | null>(null);
  const [goal, setGoal] = useState<Goal>(Goal.CASUAL);
  const [showReference, setShowReference] = useState<string>('');
  const [assessmentResult, setAssessmentResult] = useState<AssessmentResult | null>(null);

  const [socialScript, setSocialScript] = useState<string>('');
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioAnalysis, setAudioAnalysis] = useState<string>('');
  const [vibeCheck, setVibeCheck] = useState<VibeCheckContent | null>(null);

  const handleStart = useCallback((reference: string, selectedGoal: Goal) => {
    setShowReference(reference);
    setGoal(selectedGoal);
    setPhase(AppPhase.ASSESSMENT_RECORD);
  }, []);

  const handleAssessmentComplete = useCallback((result: AssessmentResult) => {
    setAssessmentResult(result);
    setLevel(result.level);
    setPhase(AppPhase.ASSESSMENT_RESULTS);
  }, []);

  const handleStartPlan = useCallback(() => {
    setPhase(AppPhase.PHASE_1_GENERATE);
  }, []);

  const handleScriptGenerated = useCallback((script: string) => {
    setSocialScript(script);
    setPhase(AppPhase.PHASE_1_RECORD);
  }, []);

  const handleRecordingComplete = useCallback((blob: Blob) => {
    setAudioBlob(blob);
    setPhase(AppPhase.PHASE_2_ANALYZE);
  }, []);

  const handleAnalysisComplete = useCallback((analysis: string) => {
    setAudioAnalysis(analysis);
    setPhase(AppPhase.PHASE_2_REVIEW);
  }, []);

  const handleContinueToVibeCheck = useCallback(() => {
    setPhase(AppPhase.PHASE_3_GENERATE);
  }, []);

  const handleVibeCheckGenerated = useCallback((vibeCheckContent: VibeCheckContent) => {
    setVibeCheck(vibeCheckContent);
    setPhase(AppPhase.PHASE_3_PRACTICE);
  }, []);

  const handleNextScript = useCallback(() => {
    // Reset state for the next round, but keep level, goal, reference
    setSocialScript('');
    setAudioBlob(null);
    setAudioAnalysis('');
    setVibeCheck(null);
    setPhase(AppPhase.PHASE_1_GENERATE);
  }, []);

  const renderContent = () => {
    switch (phase) {
      case AppPhase.WELCOME:
        return <Welcome onStart={handleStart} />;
      case AppPhase.ASSESSMENT_RECORD:
      case AppPhase.ASSESSMENT_ANALYZE:
        return <Assessment currentPhase={phase} goal={goal} onAssessmentComplete={handleAssessmentComplete} />;
      case AppPhase.ASSESSMENT_RESULTS:
        return <AssessmentResults result={assessmentResult} onStartPlan={handleStartPlan} />;
      case AppPhase.PHASE_1_GENERATE:
      case AppPhase.PHASE_1_RECORD:
        if (!level) return null; // Should not happen
        return (
          <PhaseOne
            level={level}
            showReference={showReference}
            currentPhase={phase}
            onScriptGenerated={handleScriptGenerated}
            onRecordingComplete={handleRecordingComplete}
            socialScript={socialScript}
          />
        );
      case AppPhase.PHASE_2_ANALYZE:
      case AppPhase.PHASE_2_REVIEW:
        return (
          <PhaseTwo
            currentPhase={phase}
            script={socialScript}
            audioBlob={audioBlob}
            onAnalysisComplete={handleAnalysisComplete}
            analysisResult={audioAnalysis}
            onContinue={handleContinueToVibeCheck}
          />
        );
      case AppPhase.PHASE_3_GENERATE:
      case AppPhase.PHASE_3_PRACTICE:
        return (
          <PhaseThree
            currentPhase={phase}
            script={socialScript}
            onVibeCheckGenerated={handleVibeCheckGenerated}
            vibeCheckContent={vibeCheck}
            onNextScript={handleNextScript}
          />
        );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center justify-center p-4 selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-indigo-400 tracking-tight">
            The American Cultural Insider
          </h1>
          <p className="text-gray-400 mt-2">Your coach for sounding like a local 🤙</p>
        </header>
        <main className="bg-gray-800 rounded-2xl shadow-2xl p-6 md:p-8 min-h-[400px] flex flex-col justify-center">
          {renderContent()}
        </main>
        <footer className="text-center mt-8 text-gray-500 text-sm">
          <p>Powered by Gemini. Built for a natural, authentic learning experience.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (audioBlob: Blob, goal: Goal, calibrationText: string): Promise<AssessmentResult> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's proficiency and recommend a learning track. The user's stated goal is to learn to speak more '${goal}'.`;
    const prompt = `The user read the following text: "${calibrationText}". Please analyze their audio recording for proficiency (clarity, rhythm, use of connected speech, etc.). Based on their proficiency and stated goal, return a JSON object with four keys: 'level' (one of ['The Tourist', 'The Local', 'The Insider']), 'levelNumber' (a number from 1 to 10, where 1-3 is Tourist, 4-7 is Local, 8-10 is Insider), 'feedback' (a concise, one-sentence summary of the most important area for improvement), and 'plan' (a short, one-sentence suggested startup plan).`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
                        levelNumber: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                        plan: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as AssessmentResult;
    } catch (error) {
        console.error("Error assessing user level:", error);
        return {
            level: Level.TOURIST,
            levelNumber: 1,
            feedback: "Could not analyze audio. Let's start with the basics.",
            plan: "We'll begin with fundamental pronunciation and rhythm exercises."
        };
    }
};

export const generateSocialScript = async (level: Level, showReference: string): Promise<string> => {
    const ai = getAi();
    const scriptType = ["dialogue script", "social media post", "story time narrative"][Math.floor(Math.random() * 3)];

    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. You MUST NOT use emojis.";
    const prompt = `Generate a very short, casual text (maximum one paragraph and around 50-75 words) for a language learner at '${level}' level. The text should be a ${scriptType} and include heavy natural elements like phrasal verbs, slang, and contractions appropriate for that level. ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob): Promise<string> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your goal is to help a user sound more like a native American English speaker by analyzing their audio recording of a script. Focus on connected speech, flap-t sounds, intonation, and rhythm. Prioritize flow over perfect grammar. Be encouraging and use a 'How it looks' vs 'How it sounds' format for your examples. Format your response using markdown.";
    const contents = {
        parts: [
            { text: `Here is the script the user was reading: "${script}"` },
            audioPart,
            { text: `Now, analyze the user's audio. Provide specific, markdown-formatted feedback on their pronunciation, focusing on 2-3 key areas for improvement. Use the "How it looks" vs "How it sounds" format for your examples (e.g., "How it looks: 'going to', How it sounds: 'gonna'"). Keep the feedback concise, actionable, and encouraging.` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction: systemInstruction,
            }
        });
        return response.text || "Could not analyze the audio. The AI might not have been able to process it.";
    } catch (error) {
        console.error("Error analyzing audio:", error);
        return "There was an issue analyzing your audio. Please try recording again.";
    }
};

export const generateVibeCheck = async (script: string): Promise<VibeCheckContent> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider.' Your goal is to test a user's comprehension of nuance and slang from a text they just read, and to explain the slang.";
    const prompt = `Based on this text: "${script}", generate a JSON object. This object must have three keys: 'slangBreakdown', 'questions', and 'challenge'. 'slangBreakdown' must be an array of objects, where each object has a 'term' (the slang word or phrasal verb from the text) and a 'meaning' (a clear, simple explanation). 'questions' must be an array of two strings, each a question about the underlying meaning or nuance (e.g., sarcasm, word choice). 'challenge' must be a string prompting the user to use one of the slang words in a sentence about their own life.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        slangBreakdown: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    term: { type: Type.STRING },
                                    meaning: { type: Type.STRING }
                                }
                            }
                        },
                        questions: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        },
                        challenge: {
                            type: Type.STRING
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as VibeCheckContent;
    } catch (error) {
        console.error("Error generating vibe check:", error);
        return {
            slangBreakdown: [{ term: "N/A", meaning: "Could not generate slang breakdown."}],
            questions: ["Could not generate a question. What do you think the main feeling of the text was?", "What's one word you learned?"],
            challenge: "Try using a word from the text in a sentence!"
        };
    }
};

