    setIsRecording(false);
  }, []);

  const startRecording = useCallback(async () => {
    setError(null);
    setTimer(0);
    if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaRecorderRef.current = new MediaRecorder(stream);
        audioChunksRef.current = [];

        mediaRecorderRef.current.addEventListener("dataavailable", event => {
          audioChunksRef.current.push(event.data);
        });

        mediaRecorderRef.current.addEventListener("stop", () => {
          const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
          onRecordingComplete(audioBlob);
          stream.getTracks().forEach(track => track.stop());
        });

        mediaRecorderRef.current.start();
        setIsRecording(true);
        timerIntervalRef.current = window.setInterval(() => {
            setTimer(prev => prev + 1);
        }, 1000);

        let pointIndex = 0;
        analysisIntervalRef.current = window.setInterval(() => {
            pointIndex = (pointIndex + 1) % analysisPoints.length;
            setCurrentAnalysisPoint(analysisPoints[pointIndex]);
        }, 2000);

      } catch (err) {
        console.error("Error accessing microphone:", err);
        setError("Microphone access denied. Please enable it in your browser settings.");
      }
    } else {
      setError("Audio recording is not supported by your browser.");
    }
  }, [onRecordingComplete]);

  useEffect(() => {
    if (timer >= 60) {
        stopRecording();
    }
  }, [timer, stopRecording]);

  useEffect(() => {
    return () => {
        if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
        if (analysisIntervalRef.current) clearInterval(analysisIntervalRef.current);
    }
  }, []);


  const handleToggleRecording = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  return (
    <div className="flex flex-col items-center space-y-4 w-full">
      <Button onClick={handleToggleRecording} disabled={!!error}>
        {isRecording ? (
          <span className="flex items-center space-x-2">
            <StopIcon />
            <span>Stop Recording</span>
          </span>
        ) : (
          <span className="flex items-center space-x-2">
            <MicIcon />
            <span>Start Recording</span>
          </span>
        )}
      </Button>
      {isRecording && 
        <div className="text-center">
            <div className="text-red-500 font-bold animate-pulse tabular-nums mb-2">
                Recording... {formatTime(timer)} / 01:00
            </div>
            <div className="text-indigo-300 text-sm transition-opacity duration-500">
                {currentAnalysisPoint}
            </div>
        </div>
      }
      {error && <p className="text-red-400 text-sm mt-2">{error}</p>}
    </div>
  );
};

