import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (audioBlob: Blob, goal: Goal, calibrationText: string): Promise<AssessmentResult> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's proficiency and recommend a learning track. The user's stated goal is to learn to speak more '${goal}'.`;
    const prompt = `The user read the following text: "${calibrationText}". Please analyze their audio recording for proficiency (clarity, rhythm, use of connected speech, etc.). Based on their proficiency and stated goal, return a JSON object with four keys: 'level' (one of ['The Tourist', 'The Local', 'The Insider']), 'levelNumber' (a number from 1 to 10, where 1-3 is Tourist, 4-7 is Local, 8-10 is Insider), 'feedback' (a concise, one-sentence summary of the most important area for improvement), and 'plan' (a short, one-sentence suggested startup plan).`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
                        levelNumber: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                        plan: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as AssessmentResult;
    } catch (error) {
        console.error("Error assessing user level:", error);
        return {
            level: Level.TOURIST,
            levelNumber: 1,
            feedback: "Could not analyze audio. Let's start with the basics.",
            plan: "We'll begin with fundamental pronunciation and rhythm exercises."
        };
    }
};

export const generateSocialScript = async (level: Level, showReference: string): Promise<string> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. You MUST NOT use emojis.";
    const prompt = `Generate a very short, casual text of one or two lines maximum for a language learner at '${level}' level. The text should be a dialogue line or social media post and include natural elements like phrasal verbs, slang, and contractions appropriate for that level. ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob): Promise<DetailedAudioAnalysis> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your user is a native Spanish speaker. Your goal is to help them sound more like a native American English speaker by analyzing their audio recording. You MUST provide feedback in a structured JSON format.";
    const contents = {
        parts: [
            { text: `The user read this script: "${script}"` },
            audioPart,
            { text: `Analyze the user's audio. Determine if their pronunciation was mostly correct. Identify the *single most impactful* word or short phrase they pronounced incorrectly. If it's mostly correct, you must set 'incorrectPhrase' to null. Provide general feedback, and crucially, a detailed phonetic explanation for the incorrect part, specifically for a Spanish speaker. Explain how to produce sounds that are difficult for them (like the English 'th', short 'i', 'r'). Use Spanish phonetic examples if helpful. Return a JSON object with the keys: 'isCorrect' (boolean), 'incorrectPhrase' (string or null), 'feedback' (markdown string), 'phoneticExplanation' (markdown string for Spanish speakers).` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        isCorrect: { type: Type.BOOLEAN },
                        incorrectPhrase: { type: Type.STRING },
                        feedback: { type: Type.STRING },
                        phoneticExplanation: { type: Type.STRING }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as DetailedAudioAnalysis;
    } catch (error) {
        console.error("Error analyzing audio:", error);
        return {
            isCorrect: false,
            incorrectPhrase: null,
            feedback: "There was an issue analyzing your audio. Please try recording again.",
            phoneticExplanation: "We couldn't process the audio this time. Please ensure you're in a quiet environment and try again."
        };
    }
};

export const generateVibeCheck = async (script: string): Promise<VibeCheckContent> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider.' Your goal is to test a user's comprehension of nuance and slang from a text they just read, and to explain the slang.";
    const prompt = `Based on this text: "${script}", generate a JSON object. This object must have three keys: 'slangBreakdown', 'questions', and 'challenge'. 'slangBreakdown' must be an array of objects, where each object has a 'term' (the slang word or phrasal verb from the text) and a 'meaning' (a clear, simple explanation). 'questions' must be an array of two strings, each a question about the underlying meaning or nuance (e.g., sarcasm, word choice). 'challenge' must be a string prompting the user to use one of the slang words in a sentence about their own life.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        slangBreakdown: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    term: { type: Type.STRING },
                                    meaning: { type: Type.STRING }
                                }
                            }
                        },
                        questions: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        },
                        challenge: {
                            type: Type.STRING
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as VibeCheckContent;
    } catch (error) {
        console.error("Error generating vibe check:", error);
        return {
            slangBreakdown: [{ term: "N/A", meaning: "Could not generate slang breakdown."}],
            questions: ["Could not generate a question. What do you think the main feeling of the text was?", "What's one word you learned?"],
            challenge: "Try using a word from the text in a sentence!"
        };
    }
