import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, SpokenResponseAnalysis } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (audioBlob: Blob, goal: Goal, calibrationText: string): Promise<AssessmentResult> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's proficiency and recommend a learning track. The user's stated goal is to learn to speak more '${goal}'.`;
    const prompt = `The user read the following text: "${calibrationText}". Please analyze their audio recording for proficiency (clarity, rhythm, use of connected speech, etc.). Based on their proficiency and stated goal, return a JSON object with four keys: 'level' (one of ['The Tourist', 'The Local', 'The Insider']), 'score' (a number from 1 to 100), 'feedback' (a concise, one-sentence summary of the most important area for improvement), and 'plan' (a short, one-sentence suggested startup plan).`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
                        score: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                        plan: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as AssessmentResult;
    } catch (error) {
        console.error("Error assessing user level:", error);
        return {
            level: Level.TOURIST,
            score: 20,
            feedback: "Could not analyze audio. Let's start with the basics.",
            plan: "We'll begin with fundamental pronunciation and rhythm exercises."
        };
    }
};

