const highlightIncorrectPhrase = (script: string, phrase: string | null) => {
    if (!phrase || !script.toLowerCase().includes(phrase.toLowerCase())) {
        return <span>{script}</span>;
    }
    const parts = script.split(new RegExp(`(${phrase})`, 'gi'));
    return (
        <span>
            {parts.map((part, i) =>
                part.toLowerCase() === phrase.toLowerCase() ? (
                    <span key={i} className="bg-red-500/30 text-red-200 rounded px-1 py-0.5">
                        {part}
                    </span>
                ) : (
                    part
                )
            )}
        </span>
    );
};

