import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, SpokenResponseAnalysis, AssessmentText } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (audioBlob: Blob, goal: Goal, assessmentText: AssessmentText): Promise<AssessmentResult> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's proficiency and recommend a learning track based on a diagnostic recording. The user's stated goal is to learn to speak more '${goal}'.`;
    const prompt = `The user read the following diagnostic text: "${assessmentText.text}"

This text was specifically designed to test for these phonetic features:
${JSON.stringify(assessmentText.targets, null, 2)}

In the targets above, 'sound' is the IPA phonetic notation, 'examples' are words from the text that contain the sound, and 'commonErrors' are typical mistakes non-native speakers make.

Please analyze the user's audio recording for overall proficiency (clarity, rhythm, use of connected speech, etc.), but pay special attention to their performance on the specified phonetic targets.

Based on their proficiency and stated goal, return a JSON object with four keys:
1. 'level' (one of ['The Tourist', 'The Local', 'The Insider'])
2. 'score' (an integer from 1 to 100, reflecting their accuracy on the diagnostic)
3. 'feedback' (a concise, one-sentence summary of the most important area for improvement, referencing the phonetic targets if relevant)
4. 'plan' (a short, one-sentence suggested startup plan to address the feedback).`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
                        score: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                        plan: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as AssessmentResult;
    } catch (error) {
        console.error("Error assessing user level:", error);
        return {
            level: Level.TOURIST,
            score: 20,
            feedback: "Could not analyze audio. Let's start with the basics.",
            plan: "We'll begin with fundamental pronunciation and rhythm exercises."
        };
    }
};

export const generateSocialScript = async (level: Level, showReference: string): Promise<string> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. You MUST NOT use emojis.";
    const prompt = `Generate a very short, casual text of one or two lines maximum for a language learner at '${level}' level. The text should be a dialogue line or social media post and include natural elements like phrasal verbs, slang, and contractions appropriate for that level. ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob): Promise<DetailedAudioAnalysis> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your user is a native Spanish speaker. Your goal is to help them sound more like a native American English speaker by analyzing their audio recording. You MUST provide feedback in a structured JSON format.";
    const contents = {
        parts: [
            { text: `The user read this script: "${script}"` },
            audioPart,
            { text: `Analyze the user's audio. Determine if their pronunciation was mostly correct. Identify the *single most impactful* word or short phrase they pronounced incorrectly. If it's mostly correct, you must set 'incorrectPhrase' to null. Provide general feedback, and crucially, a detailed phonetic explanation for the incorrect part, specifically for a Spanish speaker. Explain how to produce sounds that are difficult for them (like the English 'th', short 'i', 'r'). Use Spanish phonetic examples if helpful. Return a JSON object with the keys: 'isCorrect' (boolean), 'incorrectPhrase' (string or null), 'feedback' (markdown string), 'phoneticExplanation' (markdown string for Spanish speakers), and 'score' (an integer from 1 to 100).` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        isCorrect: { type: Type.BOOLEAN },
                        incorrectPhrase: { type: Type.STRING },
                        feedback: { type: Type.STRING },
                        phoneticExplanation: { type: Type.STRING },
                        score: { type: Type.INTEGER }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
