import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, SpokenResponseAnalysis, AssessmentText, PhoneticProfile } from '../types';

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const analyzeDiagnosticAudio = async (audioBlob: Blob, assessmentText: AssessmentText): Promise<{ score: number; feedback: string; }> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = `You are an expert American English pronunciation coach. Your task is to assess a user's performance on a single, specific diagnostic text.`;
    const prompt = `The user read the following diagnostic text: "${assessmentText.text}"

This text was specifically designed to test for these phonetic features:
${JSON.stringify(assessmentText.targets, null, 2)}

Please analyze the user's audio recording, focusing almost exclusively on their performance on the specified phonetic targets. 
Return a JSON object with two keys:
1. 'score' (an integer from 1 to 100, reflecting their accuracy on the diagnostic targets)
2. 'feedback' (a concise, one-sentence summary of their performance on this specific text).`;

    const contents = { parts: [audioPart, { text: prompt }] };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText);
    } catch (error) {
        console.error(`Error analyzing diagnostic audio for ${assessmentText.id}:`, error);
        return {
            score: 20,
            feedback: "Could not analyze audio for this section.",
        };
    }
};

export const generateOverallAssessment = async (profile: PhoneticProfile, goal: Goal): Promise<AssessmentResult> => {
    const ai = getAi();
    const systemInstruction = `You are an expert American English pronunciation coach. You have analyzed a user's performance across five key diagnostic areas and now must provide an overall assessment and a personalized plan. The user's stated goal is to achieve '${goal}'.`;
    const prompt = `Here is the user's detailed phonetic profile, with scores out of 100 for five diagnostic categories:
${JSON.stringify(profile, null, 2)}

Based on this detailed profile, please generate a final JSON assessment object with four keys:
1. 'level': Determine their overall proficiency level. It must be one of ['The Tourist', 'The Local', 'The Insider']. Base this on the aggregate scores.
2. 'score': Calculate an overall score from 1 to 100. This should be a weighted average, but you can approximate it as the simple average of the five scores.
3. 'feedback': Write a concise, encouraging, one-sentence summary of their overall performance.
4. 'plan': Create a personalized, one-sentence startup plan that directly addresses their 1-2 weakest areas from the profile. For example, if they scored lowest on 'th-sounds' and 'rhythm-stress', the plan should mention focusing on those.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        level: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
                        score: { type: Type.INTEGER },
                        feedback: { type: Type.STRING },
                        plan: { type: Type.STRING },
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        const result = JSON.parse(jsonText);
        return { ...result, phoneticProfile: profile };
    } catch (error) {
        console.error("Error generating overall assessment:", error);
        return {
            level: Level.TOURIST,
            score: 20,
            feedback: "Could not generate a final assessment. Let's start with the basics.",
            plan: "We'll begin with fundamental pronunciation and rhythm exercises.",
            phoneticProfile: profile,
        };
    }
}

