        <h3 className="font-bold text-indigo-300 mb-4 text-center">Profile Breakdown</h3>
        <div className="space-y-4">
          {Object.entries(result.phoneticProfile).map(([id, analysis]) => (
            <div key={id}>
              <div className="flex justify-between items-center mb-1">
                <p className="font-semibold text-white">{getCategoryName(id)}</p>
