  SLANG = 'Fluent with Slang',
}

export interface SlangTerm {
  term: string;
  meaning: string;
}

export interface VibeCheckContent {
  slangBreakdown: SlangTerm[];
  questions: string[];
  challenge: string;
}

export enum Priority {
  HIGH = 'high',
  MEDIUM = 'medium',
  LOW = 'low',
}

export enum RecommendedPath {
    CONNECTED_SPEECH = 'CONNECTED_SPEECH',
    SOUND_ACCURACY = 'SOUND_ACCURACY',
    RHYTHM_FLOW = 'RHYTHM_FLOW',
    VOCABULARY_SLANG = 'VOCABULARY_SLANG'
}

export interface PhoneticCategoryAnalysis {
    score: number; // 1-10
    feedback: string;
    priority: Priority;
}

export interface PhoneticProfile {
    flapT: PhoneticCategoryAnalysis;
    connectedSpeech: PhoneticCategoryAnalysis;
    thSounds: PhoneticCategoryAnalysis;
    vowelQuality: PhoneticCategoryAnalysis;
    rhythmStress: PhoneticCategoryAnalysis;
}

export interface AssessmentResult {
    overallLevel: number; // 1-10
    levelName: Level;
    phoneticProfile: PhoneticProfile;
    topStrength: string;
    primaryFocus: string;
    secondaryFocus: string;
    recommendedPath: RecommendedPath;
    encouragement: string;
}


export interface DetailedAudioAnalysis {
  isCorrect: boolean;
  incorrectPhrase: string | null;
  feedback: string;
  phoneticExplanation: string;
  score: number;
}

export interface SpokenResponseAnalysis {
    feedback: string;
    score: number;
}

export interface PhoneticTarget {
  sound: string;           // IPA notation
  examples: string[];      // words in the text
  commonErrors: string[];  // what non-natives typically do wrong
}

export interface AssessmentText {
  id: string;
  text: string;
  targets: PhoneticTarget[];
  difficulty: 'diagnostic';
}

import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, SpokenResponseAnalysis, AssessmentText, RecommendedPath, Priority } from '../types';
import { LEVEL_DEFINITIONS } from "../data/levels";

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (
  audioBlobs: Blob[],
  goal: Goal,
  assessmentTexts: AssessmentText[]
): Promise<AssessmentResult> => {
  const ai = getAi();
  const audioParts = await Promise.all(audioBlobs.map(fileToGenerativePart));

  const systemInstruction = `You are an expert American English pronunciation diagnostician with a PhD in phonetics. You analyze speech patterns with clinical precision. You understand IPA notation and can identify specific phonetic errors.

Your analysis must be:
- Specific (use IPA when relevant)
- Actionable (identify exactly what needs to change)
- Encouraging (celebrate strengths, frame weaknesses as opportunities)

The user wants to achieve: ${goal === Goal.CASUAL ? 'clear, natural American speech' : 'fluent American speech with slang mastery'}.`;

  const prompt = `Analyze these ${audioBlobs.length} recordings as a comprehensive pronunciation assessment.

For each recording, the user read:
${assessmentTexts.map((t, i) => `Recording ${i + 1} (for assessing '${t.id}'): "${t.text}"\nTargets: ${t.targets.map(tgt => tgt.sound).join(', ')}`).join('\n\n')}

Here are the detailed definitions for the proficiency levels. Use these criteria to determine the user's 'overallLevel' (1-10) and 'levelName'.
${JSON.stringify(LEVEL_DEFINITIONS, null, 2)}

Based on your analysis of the audio against the phonetic targets AND the level definitions provided, return a JSON object with this exact structure:
{
  "overallLevel": number (1-10),
  "levelName": "Tourist" | "Local" | "Insider",
  "phoneticProfile": {
    "flapT": { "score": 1-10, "feedback": "specific feedback", "priority": "high" | "medium" | "low" },
    "connectedSpeech": { "score": 1-10, "feedback": "...", "priority": "..." },
    "thSounds": { "score": 1-10, "feedback": "...", "priority": "..." },
    "vowelQuality": { "score": 1-10, "feedback": "...", "priority": "..." },
    "rhythmStress": { "score": 1-10, "feedback": "...", "priority": "..." }
  },
  "topStrength": "string describing their best area",
  "primaryFocus": "the ONE thing to work on first",
  "secondaryFocus": "the second priority",
  "recommendedPath": "CONNECTED_SPEECH" | "SOUND_ACCURACY" | "RHYTHM_FLOW" | "VOCABULARY_SLANG",
  "encouragement": "personalized motivational message"
}`;

  const phoneticCategorySchema = {
    type: Type.OBJECT,
    properties: {
        score: { type: Type.INTEGER },
        feedback: { type: Type.STRING },
        priority: { type: Type.STRING, enum: [Priority.HIGH, Priority.MEDIUM, Priority.LOW] },
    }
  };

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
        overallLevel: { type: Type.INTEGER },
        levelName: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
        phoneticProfile: {
            type: Type.OBJECT,
            properties: {
                flapT: phoneticCategorySchema,
                connectedSpeech: phoneticCategorySchema,
                thSounds: phoneticCategorySchema,
                vowelQuality: phoneticCategorySchema,
                rhythmStress: phoneticCategorySchema,
            }
        },
        topStrength: { type: Type.STRING },
        primaryFocus: { type: Type.STRING },
        secondaryFocus: { type: Type.STRING },
        recommendedPath: { type: Type.STRING, enum: [RecommendedPath.CONNECTED_SPEECH, RecommendedPath.SOUND_ACCURACY, RecommendedPath.RHYTHM_FLOW, RecommendedPath.VOCABULARY_SLANG] },
        encouragement: { type: Type.STRING },
    }
  };

  const contents = {
      parts: [...audioParts, { text: prompt }],
  };

  try {
      const response: GenerateContentResponse = await ai.models.generateContent({
          model: 'gemini-3-pro-preview', // Use a more powerful model for this complex task
          contents,
          config: {
              systemInstruction,
              responseMimeType: 'application/json',
              responseSchema,
          }
      });
      const jsonText = response.text || '{}';
      return JSON.parse(jsonText) as AssessmentResult;
  } catch (error) {
      console.error("Error assessing user level:", error);
      // Fallback result in case of an error
      return {
          overallLevel: 3,
          levelName: Level.TOURIST,
          phoneticProfile: {
              flapT: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              connectedSpeech: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              thSounds: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              vowelQuality: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              rhythmStress: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
          },
          topStrength: "Persistence!",
          primaryFocus: "Basic pronunciation.",
          secondaryFocus: "Speaking rhythm.",
          recommendedPath: RecommendedPath.SOUND_ACCURACY,
          encouragement: "We couldn't analyze your audio, but don't worry! Let's start with the fundamentals together.",
      };
  }
};

export const generateSocialScript = async (level: Level, showReference: string): Promise<string> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider,' a cool, savvy language coach specializing in natural, casual American English. Your tone is energetic and real. You MUST NOT use emojis.";
    const prompt = `Generate a very short, casual text of one or two lines maximum for a language learner at '${level}' level. The text should be a dialogue line or social media post and include natural elements like phrasal verbs, slang, and contractions appropriate for that level. ${showReference ? `The style should be reminiscent of the way people talk in '${showReference}'.` : ''}`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction: systemInstruction,
            },
        });
        return response.text || "Couldn't generate a script. Please try again.";
    } catch (error) {
        console.error("Error generating social script:", error);
        return "There was an issue connecting to the AI. Please check your connection and API key.";
    }
};

export const analyzeAudio = async (script: string, audioBlob: Blob): Promise<DetailedAudioAnalysis> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are 'The American Cultural Insider,' an expert pronunciation coach. Your user is a native Spanish speaker. Your goal is to help them sound more like a native American English speaker by analyzing their audio recording. You MUST provide feedback in a structured JSON format.";
    const contents = {
        parts: [
            { text: `The user read this script: "${script}"` },
            audioPart,
            { text: `Analyze the user's audio. Determine if their pronunciation was mostly correct. Identify the *single most impactful* word or short phrase they pronounced incorrectly. If it's mostly correct, you must set 'incorrectPhrase' to null. Provide general feedback, and crucially, a detailed phonetic explanation for the incorrect part, specifically for a Spanish speaker. Explain how to produce sounds that are difficult for them (like the English 'th', short 'i', 'r'). Use Spanish phonetic examples if helpful. Return a JSON object with the keys: 'isCorrect' (boolean), 'incorrectPhrase' (string or null), 'feedback' (markdown string), 'phoneticExplanation' (markdown string for Spanish speakers), and 'score' (an integer from 1 to 100).` }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        isCorrect: { type: Type.BOOLEAN },
                        incorrectPhrase: { type: Type.STRING },
                        feedback: { type: Type.STRING },
                        phoneticExplanation: { type: Type.STRING },
                        score: { type: Type.INTEGER }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as DetailedAudioAnalysis;
    } catch (error) {
        console.error("Error analyzing audio:", error);
        return {
            isCorrect: false,
            incorrectPhrase: null,
            feedback: "There was an issue analyzing your audio. Please try recording again.",
            phoneticExplanation: "We couldn't process the audio this time. Please ensure you're in a quiet environment and try again.",
            score: 0
        };
    }
};

export const generateVibeCheck = async (script: string): Promise<VibeCheckContent> => {
    const ai = getAi();
    const systemInstruction = "You are 'The American Cultural Insider.' Your goal is to test a user's comprehension of nuance and slang from a text they just read, and to explain the slang.";
    const prompt = `Based on this text: "${script}", generate a JSON object. This object must have three keys: 'slangBreakdown', 'questions', and 'challenge'. 'slangBreakdown' must be an array of objects, where each object has a 'term' (the slang word or phrasal verb from the text) and a 'meaning' (a clear, simple explanation). 'questions' must be an array of two strings, each a question about the underlying meaning or nuance (e.g., sarcasm, word choice) for the user to think about. 'challenge' must be a string prompting the user to use one of the slang words in a spoken sentence about their own life.`;

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        slangBreakdown: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    term: { type: Type.STRING },
                                    meaning: { type: Type.STRING }
                                }
                            }
                        },
                        questions: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        },
                        challenge: {
                            type: Type.STRING
                        }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as VibeCheckContent;
    } catch (error) {
        console.error("Error generating vibe check:", error);
        return {
            slangBreakdown: [{ term: "N/A", meaning: "Could not generate slang breakdown."}],
            questions: ["Could not generate a question. What do you think the main feeling of the text was?", "What's one word you learned?"],
            challenge: "Try using a word from the text in a sentence!"
        };
    }
};


export const analyzeSpokenResponse = async (challenge: string, audioBlob: Blob): Promise<SpokenResponseAnalysis> => {
    const ai = getAi();
    const audioPart = await fileToGenerativePart(audioBlob);

    const systemInstruction = "You are an American English coach. You are analyzing a user's spoken response to a challenge question. Your feedback should be encouraging and focus on clarity and correct use of slang.";
    const prompt = `The challenge was: "${challenge}". The user responded with this audio. Please analyze their response for clarity, confidence, and correct use of any target slang. Provide a score from 1-100 and brief, encouraging feedback. Return a JSON object with 'score' (integer) and 'feedback' (string) keys.`;

    const contents = {
        parts: [
            audioPart,
            { text: prompt }
        ]
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.INTEGER },
                        feedback: { type: Type.STRING }
                    }
                }
            }
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as SpokenResponseAnalysis;
    } catch (error) {
        console.error("Error analyzing spoken response:", error);
        return {
            score: 0,
            feedback: "There was an issue analyzing your spoken response. Please try recording again.",
        };
    }
};

import React from 'react';
import { AssessmentResult, PhoneticProfile, Priority, RecommendedPath } from '../types';
import { Button } from './ui/Button';
import { ScoreBar } from './ui/ScoreBar';
import { LEVEL_DEFINITIONS } from '../data/levels';

interface AssessmentResultsProps {
  result: AssessmentResult | null;
  onStartPlan: () => void;
}

const categoryDisplayMap: Record<keyof PhoneticProfile, string> = {
  flapT: 'Flap T Sound',
  connectedSpeech: 'Connected Speech',
  thSounds: 'TH Sounds',
  vowelQuality: 'Vowel Quality',
  rhythmStress: 'Rhythm & Stress',
};

const pathDisplayMap: Record<RecommendedPath, { title: string, description: string }> = {
    [RecommendedPath.SOUND_ACCURACY]: { title: "Sound Accuracy", description: "Focus on mastering individual English sounds." },
    [RecommendedPath.CONNECTED_SPEECH]: { title: "Connected Speech", description: "Learn to link words together smoothly." },
    [RecommendedPath.RHYTHM_FLOW]: { title: "Rhythm & Flow", description: "Work on sentence stress and intonation." },
    [RecommendedPath.VOCABULARY_SLANG]: { title: "Vocabulary & Slang", description: "Expand your word choice and cultural fluency." },
};

const PriorityBadge: React.FC<{ priority: Priority }> = ({ priority }) => {
    const styles = {
        [Priority.HIGH]: 'bg-red-500/80 border-red-400',
        [Priority.MEDIUM]: 'bg-yellow-500/80 border-yellow-400',
        [Priority.LOW]: 'bg-green-500/80 border-green-400',
    }
    return <span className={`px-2 py-0.5 text-xs font-semibold text-white rounded-full border ${styles[priority]}`}>{priority}</span>
}

const AssessmentResults: React.FC<AssessmentResultsProps> = ({ result, onStartPlan }) => {
  if (!result) {
    return (
      <div className="text-center">
        <p>Loading assessment results...</p>
      </div>
    );
  }

  const levelDef = LEVEL_DEFINITIONS.find(def => def.name === result.levelName);

  return (
    <div className="flex flex-col items-center text-center animate-fade-in space-y-6">
      <h2 className="text-2xl font-bold text-white">Here's Your Detailed Profile</h2>

      <div className="w-full max-w-sm">
        <div className="bg-gray-700 rounded-lg p-4">
          <p className="text-gray-400 text-sm">Your Overall Score</p>
          <p className="text-4xl font-bold text-indigo-400">{result.overallLevel * 10} / 100</p>
          <p className="text-lg font-semibold text-white">{result.levelName}</p>
        </div>
      </div>

      {levelDef && (
        <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
          <h3 className="font-bold text-indigo-300 mb-2 text-xl text-center">{levelDef.name} Level</h3>
          <p className="text-center text-gray-300 italic mb-4">"{levelDef.description}"</p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
            <div className="bg-gray-800/50 p-3 rounded">
              <h4 className="font-semibold text-white mb-2">✅ What you can do:</h4>
              <ul className="list-disc list-inside text-gray-300 space-y-1">
                {levelDef.canDo.map((item, i) => <li key={i}>{item}</li>)}
              </ul>
            </div>
            <div className="bg-gray-800/50 p-3 rounded">
              <h4 className="font-semibold text-white mb-2">💪 What you're working on:</h4>
              <ul className="list-disc list-inside text-gray-300 space-y-1">
                {levelDef.workingOn.map((item, i) => <li key={i}>{item}</li>)}
              </ul>
            </div>
          </div>
          <div className="text-center mt-3">
             <p className="text-xs text-gray-400">Target time to next level: <span className="font-semibold">{levelDef.targetTimeToNextLevel}</span></p>
          </div>
        </div>
      )}

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-4 text-center">Phonetic Breakdown</h3>
        <div className="space-y-4">
          {(Object.keys(result.phoneticProfile) as Array<keyof PhoneticProfile>).map((key) => {
            const analysis = result.phoneticProfile[key];
            return (
              <div key={key}>
                <div className="flex justify-between items-center mb-1">
                  <p className="font-semibold text-white">{categoryDisplayMap[key]}</p>
                  <div className="flex items-center space-x-2">
                    <p className="font-medium text-gray-300">{analysis.score * 10} / 100</p>
                    <PriorityBadge priority={analysis.priority} />
                  </div>
                </div>
                <ScoreBar score={analysis.score * 10} />
                <p className="text-xs text-gray-400 mt-1 italic">"{analysis.feedback}"</p>
              </div>
            );
          })}
        </div>
      </div>

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-2">Key Takeaways</h3>
        <div className="space-y-2 text-sm">
            <p><strong className="text-green-400">👍 Top Strength:</strong> {result.topStrength}</p>
            <p><strong className="text-yellow-400">🎯 Primary Focus:</strong> {result.primaryFocus}</p>
            <p><strong className="text-blue-400">👀 Secondary Focus:</strong> {result.secondaryFocus}</p>
        </div>
      </div>

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-2">Your Recommended Path</h3>
        <p className="text-white font-semibold">{pathDisplayMap[result.recommendedPath].title}</p>
        <p className="text-gray-300 text-sm mb-3">{pathDisplayMap[result.recommendedPath].description}</p>
        <p className="text-gray-200 italic">"{result.encouragement}"</p>
      </div>

      <Button onClick={onStartPlan}>
        Let's Start My Plan!
      </Button>
    </div>
  );
};

export default AssessmentResults;

