import React, { useState, useCallback, useEffect } from 'react';
import { AppPhase, Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, LearningPathDefinition } from './types';
import { ASSESSMENT_TEXTS } from './data/assessmentTexts';
import { LEARNING_PATHS } from './data/learningPaths';
import { assessUserLevel } from './services/geminiService';
import Welcome from './components/Welcome';
import Assessment from './components/Assessment';
import AssessmentResults from './components/AssessmentResults';
import LearningPathOverview from './components/LearningPathOverview';
import PathComplete from './components/PathComplete';
import PhaseOne from './components/PhaseOne';
import PhaseTwo from './components/PhaseTwo';
import PhaseThree from './components/PhaseThree';

const App: React.FC = () => {
  const [phase, setPhase] = useState<AppPhase>(AppPhase.WELCOME);
  const [level, setLevel] = useState<Level | null>(null);
  const [goal, setGoal] = useState<Goal>(Goal.CASUAL);
  const [showReference, setShowReference] = useState<string>('');
  const [assessmentResult, setAssessmentResult] = useState<AssessmentResult | null>(null);

  // Diagnostic flow state
  const [assessmentIndex, setAssessmentIndex] = useState(0);
  const [diagnosticRecordings, setDiagnosticRecordings] = useState<Blob[]>([]);

  // Learning Path state
  const [currentLearningPath, setCurrentLearningPath] = useState<LearningPathDefinition | null>(null);
  const [currentModuleIndex, setCurrentModuleIndex] = useState(0);

  // Main practice loop state
  const [socialScript, setSocialScript] = useState<string>('');
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioAnalysis, setAudioAnalysis] = useState<DetailedAudioAnalysis | null>(null);
  const [vibeCheck, setVibeCheck] = useState<VibeCheckContent | null>(null);

  const handleStart = useCallback((reference: string, selectedGoal: Goal) => {
    setShowReference(reference);
    setGoal(selectedGoal);
    setPhase(AppPhase.ASSESSMENT_RECORD);
  }, []);

  const handleSingleRecordingComplete = useCallback((recording: Blob) => {
    const newRecordings = [...diagnosticRecordings, recording];
    setDiagnosticRecordings(newRecordings);

    if (assessmentIndex < ASSESSMENT_TEXTS.length - 1) {
      setAssessmentIndex(prev => prev + 1);
    } else {
      setPhase(AppPhase.ASSESSMENT_ANALYZE);
    }
  }, [diagnosticRecordings, assessmentIndex]);

  useEffect(() => {
    const runAnalysis = async () => {
      if (phase === AppPhase.ASSESSMENT_ANALYZE && diagnosticRecordings.length === ASSESSMENT_TEXTS.length) {
        const finalAssessment = await assessUserLevel(diagnosticRecordings, goal, ASSESSMENT_TEXTS);
        setAssessmentResult(finalAssessment);
        setLevel(finalAssessment.levelName);
        setPhase(AppPhase.ASSESSMENT_RESULTS);
      }
    };
    runAnalysis();
  }, [phase, diagnosticRecordings, goal]);

  const handleStartPlan = useCallback(() => {
    if (assessmentResult) {
      const path = LEARNING_PATHS.find(p => p.path === assessmentResult.recommendedPath);
      if (path) {
        setCurrentLearningPath(path);
        setCurrentModuleIndex(0);
        setPhase(AppPhase.LEARNING_PATH_OVERVIEW);
      } else {
        // Fallback if path not found
        setPhase(AppPhase.PHASE_1_GENERATE);
      }
    }
  }, [assessmentResult]);

  const handleStartModule = useCallback(() => {
    setPhase(AppPhase.PHASE_1_GENERATE);
  }, []);

  const handleScriptGenerated = useCallback((script: string) => {
    setSocialScript(script);
    setPhase(AppPhase.PHASE_1_RECORD);
  }, []);

  const handleRecordingComplete = useCallback((blob: Blob) => {
    setAudioBlob(blob);
    setPhase(AppPhase.PHASE_2_ANALYZE);
  }, []);

  const handleAnalysisComplete = useCallback((analysis: DetailedAudioAnalysis) => {
    setAudioAnalysis(analysis);
    setPhase(AppPhase.PHASE_2_REVIEW);
  }, []);

  const handleContinueToVibeCheck = useCallback(() => {
    setPhase(AppPhase.PHASE_3_GENERATE);
  }, []);

  const handleVibeCheckGenerated = useCallback((vibeCheckContent: VibeCheckContent) => {
    setVibeCheck(vibeCheckContent);
    setPhase(AppPhase.PHASE_3_PRACTICE);
  }, []);

  const handleNextScript = useCallback(() => {
    // Reset script-specific state
    setSocialScript('');
    setAudioBlob(null);
    setAudioAnalysis(null);
    setVibeCheck(null);

    if (currentLearningPath && currentModuleIndex < currentLearningPath.modules.length - 1) {
      // Go to the next module
      setCurrentModuleIndex(prev => prev + 1);
      setPhase(AppPhase.PHASE_1_GENERATE);
    } else {
      // Path is complete
      setPhase(AppPhase.PATH_COMPLETE);
    }
  }, [currentLearningPath, currentModuleIndex]);

  const handleRestart = useCallback(() => {
      window.location.reload();
  }, []);

  const renderContent = () => {
    switch (phase) {
      case AppPhase.WELCOME:
        return <Welcome onStart={handleStart} />;
      case AppPhase.ASSESSMENT_RECORD:
      case AppPhase.ASSESSMENT_ANALYZE:
        return (
          <Assessment 
            currentPhase={phase} 
            assessmentIndex={assessmentIndex}
            onSingleRecordingComplete={handleSingleRecordingComplete}
            onAllRecordingsComplete={() => {}} // Not used in this flow
          />
        );
      case AppPhase.ASSESSMENT_RESULTS:
        return <AssessmentResults result={assessmentResult} onStartPlan={handleStartPlan} />;
      case AppPhase.LEARNING_PATH_OVERVIEW:
        if (!currentLearningPath) return null;
        return <LearningPathOverview learningPath={currentLearningPath} onStartModule={handleStartModule} />;
      case AppPhase.PATH_COMPLETE:
        return <PathComplete onRestart={handleRestart} />;
      case AppPhase.PHASE_1_GENERATE:
      case AppPhase.PHASE_1_RECORD:
        if (!level || !currentLearningPath) return null;
        return (
          <PhaseOne
            level={level}
            showReference={showReference}
            currentPhase={phase}
            module={currentLearningPath.modules[currentModuleIndex]}
            moduleNumber={currentModuleIndex + 1}
            onScriptGenerated={handleScriptGenerated}
            onRecordingComplete={handleRecordingComplete}
            socialScript={socialScript}
          />
        );
      case AppPhase.PHASE_2_ANALYZE:
      case AppPhase.PHASE_2_REVIEW:
        return (
          <PhaseTwo
            currentPhase={phase}
            script={socialScript}
            audioBlob={audioBlob}
            onAnalysisComplete={handleAnalysisComplete}
            analysisResult={audioAnalysis}
            onContinue={handleContinueToVibeCheck}
          />
        );
      case AppPhase.PHASE_3_GENERATE:
      case AppPhase.PHASE_3_PRACTICE:
        return (
          <PhaseThree
            currentPhase={phase}
            script={socialScript}
            onVibeCheckGenerated={handleVibeCheckGenerated}
            vibeCheckContent={vibeCheck}
            onNextScript={handleNextScript}
          />
        );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center justify-center p-4 selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-indigo-400 tracking-tight">
            The American Cultural Insider
          </h1>
          <p className="text-gray-400 mt-2">Your coach for sounding like a local 🤙</p>
        </header>
        <main className="bg-gray-800 rounded-2xl shadow-2xl p-6 md:p-8 min-h-[400px] flex flex-col justify-center">
          {renderContent()}
        </main>
        <footer className="text-center mt-8 text-gray-500 text-sm">
          <p>Powered by Gemini. Built for a natural, authentic learning experience.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { generateSocialScript } from '../services/geminiService';
import { AppPhase, Level, PathModule } from '../types';
import { Spinner } from './ui/Spinner';
import { Recorder } from './ui/Recorder';

interface PhaseOneProps {
  level: Level;
  showReference: string;
  currentPhase: AppPhase;
  module: PathModule;
  moduleNumber: number;
  onScriptGenerated: (script: string) => void;
  onRecordingComplete: (blob: Blob) => void;
  socialScript: string;
}

const PhaseOne: React.FC<PhaseOneProps> = ({ level, showReference, currentPhase, module, moduleNumber, onScriptGenerated, onRecordingComplete, socialScript }) => {
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (currentPhase === AppPhase.PHASE_1_GENERATE) {
      const fetchScript = async () => {
        try {
          const script = await generateSocialScript(level, showReference, module);
          onScriptGenerated(script);
        } catch (e) {
          setError('Failed to generate script. Please try again.');
          console.error(e);
        }
      };
      fetchScript();
    }
    // eslint-disable-next-line react-hooks-exhaustive-deps
  }, [currentPhase, module]);

  if (currentPhase === AppPhase.PHASE_1_GENERATE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Cooking up a targeted script for you...</p>
        <p className="mt-1 text-sm text-gray-500">Current Module: {module.name}</p>
      </div>
    );
  }

  if (error) {
    return <p className="text-red-400 text-center">{error}</p>;
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6">
      <div className="w-full text-center">
        <h2 className="text-xl font-bold text-indigo-400">Module {moduleNumber}: {module.name}</h2>
        <p className="text-gray-400 mt-1">Focus on: {module.objectives.join(', ')}</p>
      </div>

      <div className="w-full p-4 bg-gray-700/50 rounded-lg max-h-60 overflow-y-auto">
        <p className="text-gray-200 whitespace-pre-wrap leading-relaxed">{socialScript}</p>
      </div>
      <p className="text-center text-gray-300">
        Record yourself reading this out loud. Try to focus on this module's objectives.
      </p>
      <Recorder onRecordingComplete={onRecordingComplete} />
    </div>
  );
};

export default PhaseOne;

import React from 'react';
// FIX: Changed RecommendedPath to LearningPath as it is the correct type name.
import { AssessmentResult, PhoneticProfile, Priority, LearningPath } from '../types';
import { Button } from './ui/Button';
import { ScoreBar } from './ui/ScoreBar';
import { LEVEL_DEFINITIONS } from '../data/levels';

interface AssessmentResultsProps {
  result: AssessmentResult | null;
  onStartPlan: () => void;
}

const categoryDisplayMap: Record<keyof PhoneticProfile, string> = {
  flapT: 'Flap T Sound',
  connectedSpeech: 'Connected Speech',
  thSounds: 'TH Sounds',
  vowelQuality: 'Vowel Quality',
  rhythmStress: 'Rhythm & Stress',
};

const pathDisplayMap: Record<LearningPath, { title: string, description: string }> = {
    [LearningPath.SOUND_ACCURACY]: { title: "Sound Accuracy", description: "Focus on mastering individual English sounds." },
    [LearningPath.CONNECTED_SPEECH]: { title: "Connected Speech", description: "Learn to link words together smoothly." },
    [LearningPath.RHYTHM_FLOW]: { title: "Rhythm & Flow", description: "Work on sentence stress and intonation." },
    [LearningPath.VOCABULARY_SLANG]: { title: "Vocabulary & Slang", description: "Expand your word choice and cultural fluency." },
};

const PriorityBadge: React.FC<{ priority: Priority }> = ({ priority }) => {
    const styles = {
        [Priority.HIGH]: 'bg-red-500/80 border-red-400',
        [Priority.MEDIUM]: 'bg-yellow-500/80 border-yellow-400',
        [Priority.LOW]: 'bg-green-500/80 border-green-400',
    }
    return <span className={`px-2 py-0.5 text-xs font-semibold text-white rounded-full border ${styles[priority]}`}>{priority}</span>
}

const AssessmentResults: React.FC<AssessmentResultsProps> = ({ result, onStartPlan }) => {
  if (!result) {
    return (
      <div className="text-center">
        <p>Loading assessment results...</p>
      </div>
    );
  }

  const levelDef = LEVEL_DEFINITIONS.find(def => def.name === result.levelName);

  return (
    <div className="flex flex-col items-center text-center animate-fade-in space-y-6">
      <h2 className="text-2xl font-bold text-white">Here's Your Detailed Profile</h2>

      <div className="w-full max-w-sm">
        <div className="bg-gray-700 rounded-lg p-4">
          <p className="text-gray-400 text-sm">Your Overall Score</p>
          <p className="text-4xl font-bold text-indigo-400">{result.overallLevel * 10} / 100</p>
          <p className="text-lg font-semibold text-white">{result.levelName}</p>
        </div>
      </div>

      {levelDef && (
        <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
          <h3 className="font-bold text-indigo-300 mb-2 text-xl text-center">{levelDef.name} Level</h3>
          <p className="text-center text-gray-300 italic mb-4">"{levelDef.description}"</p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
            <div className="bg-gray-800/50 p-3 rounded">
              <h4 className="font-semibold text-white mb-2">✅ What you can do:</h4>
              <ul className="list-disc list-inside text-gray-300 space-y-1">
                {levelDef.canDo.map((item, i) => <li key={i}>{item}</li>)}
              </ul>
            </div>
            <div className="bg-gray-800/50 p-3 rounded">
              <h4 className="font-semibold text-white mb-2">💪 What you're working on:</h4>
              <ul className="list-disc list-inside text-gray-300 space-y-1">
                {levelDef.workingOn.map((item, i) => <li key={i}>{item}</li>)}
              </ul>
            </div>
          </div>
          <div className="text-center mt-3">
             <p className="text-xs text-gray-400">Target time to next level: <span className="font-semibold">{levelDef.targetTimeToNextLevel}</span></p>
          </div>
        </div>
      )}

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-4 text-center">Phonetic Breakdown</h3>
        <div className="space-y-4">
          {(Object.keys(result.phoneticProfile) as Array<keyof PhoneticProfile>).map((key) => {
            const analysis = result.phoneticProfile[key];
            return (
              <div key={key}>
                <div className="flex justify-between items-center mb-1">
                  <p className="font-semibold text-white">{categoryDisplayMap[key]}</p>
                  <div className="flex items-center space-x-2">
                    <p className="font-medium text-gray-300">{analysis.score * 10} / 100</p>
                    <PriorityBadge priority={analysis.priority} />
                  </div>
                </div>
                <ScoreBar score={analysis.score * 10} />
                <p className="text-xs text-gray-400 mt-1 italic">"{analysis.feedback}"</p>
              </div>
            );
          })}
        </div>
      </div>

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-2">Key Takeaways</h3>
        <div className="space-y-2 text-sm">
            <p><strong className="text-green-400">👍 Top Strength:</strong> {result.topStrength}</p>
            <p><strong className="text-yellow-400">🎯 Primary Focus:</strong> {result.primaryFocus}</p>
            <p><strong className="text-blue-400">👀 Secondary Focus:</strong> {result.secondaryFocus}</p>
        </div>
      </div>

      <div className="w-full text-left bg-gray-700/50 p-4 rounded-lg">
        <h3 className="font-bold text-indigo-300 mb-2">Your Recommended Path</h3>
        <p className="text-white font-semibold">{pathDisplayMap[result.recommendedPath].title}</p>
        <p className="text-gray-300 text-sm mb-3">{pathDisplayMap[result.recommendedPath].description}</p>
        <p className="text-gray-200 italic">"{result.encouragement}"</p>
      </div>

      <Button onClick={onStartPlan}>
        Let's Start My Plan!
      </Button>
    </div>
  );
};

export default AssessmentResults;

