interface PhaseThreeProps {
  currentPhase: AppPhase;
  exercise: Exercise;
  onVibeCheckGenerated: (vibeCheck: VibeCheckContent) => void;
  vibeCheckContent: VibeCheckContent | null;
  onNextScript: () => void;
}

const PhaseThree: React.FC<PhaseThreeProps> = ({ currentPhase, exercise, onVibeCheckGenerated, vibeCheckContent, onNextScript }) => {
  const [error, setError] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<SpokenResponseAnalysis | null>(null);

  const script = exercise.content.text;

  useEffect(() => {
    if (currentPhase === AppPhase.PHASE_3_GENERATE) {
      const getVibeCheck = async () => {
        try {
          const content = await generateVibeCheck(script);
          onVibeCheckGenerated(content);
        } catch (e) {
          setError('Failed to generate vibe check. Please try again.');
          console.error(e);
        }
      };
      getVibeCheck();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPhase]);

  const handleChallengeRecording = useCallback(async (audioBlob: Blob) => {
    if (!vibeCheckContent?.challenge) return;
    setIsAnalyzing(true);
    try {
      const result = await analyzeSpokenResponse(vibeCheckContent.challenge, audioBlob);
      setAnalysisResult(result);
    } catch (e) {
      setError('Failed to analyze your response. Please try again.');
      console.error(e);
    } finally {
      setIsAnalyzing(false);
    }
  }, [vibeCheckContent?.challenge]);

  if (currentPhase === AppPhase.PHASE_3_GENERATE) {
    return (
      <div className="flex flex-col items-center justify-center text-center">
        <Spinner />
        <p className="mt-4 text-gray-400">Prepping your vibe check...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center">
        <p className="text-red-400">{error}</p>
        <Button onClick={onNextScript} className="mt-4">Try a new script</Button>
      </div>
    );
  }

  if (!vibeCheckContent) {
    return (
        <div className="flex flex-col items-center justify-center text-center">
            <Spinner />
            <p className="mt-4 text-gray-400">Loading content...</p>
        </div>
    );
  }

  return (
    <div className="flex flex-col items-center animate-fade-in space-y-6 w-full">
      <h2 className="text-xl font-bold text-indigo-400">Phase 3: The Vibe Check</h2>

      {vibeCheckContent.slangBreakdown?.length > 0 && (
        <div className="w-full p-4 bg-gray-700/50 rounded-lg">
          <h3 className="font-bold text-lg text-indigo-300 mb-2">Slang Breakdown</h3>
          <dl>
            {vibeCheckContent.slangBreakdown.map((item, index) => (
              <div key={index} className="mb-2">
                <dt className="font-semibold text-white">{item.term}</dt>
                <dd className="text-gray-300 ml-4">{item.meaning}</dd>
              </div>
            ))}
          </dl>
        </div>
      )}

      <div className="w-full p-4 bg-gray-700/50 rounded-lg">
        <h3 className="font-bold text-lg text-indigo-300 mb-2">Think About It...</h3>
        <ul className="list-disc list-inside text-gray-300 space-y-1">
          {vibeCheckContent.questions.map((q, i) => <li key={i}>{q}</li>)}
        </ul>
      </div>

      <div className="w-full p-4 bg-blue-900/40 border border-blue-500/50 rounded-lg text-center">
        <h3 className="font-bold text-lg text-blue-300 mb-2">Your Turn!</h3>
        <p className="text-gray-200 mb-4">{vibeCheckContent.challenge}</p>

        {isAnalyzing ? (
            <div className="flex flex-col items-center justify-center text-center">
                <Spinner />
                <p className="mt-4 text-gray-400">Checking your vibe...</p>
            </div>
        ) : !analysisResult ? (
            <Recorder onRecordingComplete={handleChallengeRecording} />
        ) : (
            <div className="animate-fade-in text-center">
                <div className="bg-gray-700 rounded-lg px-3 py-2 inline-block mb-4">
                    <span className="text-gray-400 text-sm">Your Score: </span>
                    <span className="text-2xl font-bold text-indigo-400">{analysisResult.score}</span>
                    <span className="text-gray-400">/100</span>
                </div>
                <p className="text-gray-200 italic">"{analysisResult.feedback}"</p>
            </div>
        )}
      </div>

      {analysisResult && (
        <Button onClick={onNextScript} className="mt-4">
          Great Job! Next Script
        </Button>
      )}
    </div>
  );
};

export default PhaseThree;

import React, { useState, useCallback } from 'react';
