import { GoogleGenAI, GenerateContentResponse, Type, Modality } from "@google/genai";
import { Level, VibeCheckContent, Goal, AssessmentResult, DetailedAudioAnalysis, SpokenResponseAnalysis, AssessmentText, LearningPath, Priority, PathModule, Exercise, ExerciseType } from '../types';
import { LEVEL_DEFINITIONS } from "../data/levels";

const getAi = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
}

const fileToGenerativePart = async (file: Blob) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
}

export const assessUserLevel = async (
  audioBlobs: Blob[],
  goal: Goal,
  assessmentTexts: AssessmentText[]
): Promise<AssessmentResult> => {
  const ai = getAi();
  const audioParts = await Promise.all(audioBlobs.map(fileToGenerativePart));

  const systemInstruction = `You are an expert American English pronunciation diagnostician with a PhD in phonetics. You analyze speech patterns with clinical precision. You understand IPA notation and can identify specific phonetic errors.

Your analysis must be:
- Specific (use IPA when relevant)
- Actionable (identify exactly what needs to change)
- Encouraging (celebrate strengths, frame weaknesses as opportunities)

The user wants to achieve: ${goal === Goal.CASUAL ? 'clear, natural American speech' : 'fluent American speech with slang mastery'}.`;

  const prompt = `Analyze these ${audioBlobs.length} recordings as a comprehensive pronunciation assessment.

For each recording, the user read:
${assessmentTexts.map((t, i) => `Recording ${i + 1} (for assessing '${t.id}'): "${t.text}"\nTargets: ${t.targets.map(tgt => tgt.sound).join(', ')}`).join('\n\n')}

Here are the detailed definitions for the proficiency levels. Use these criteria to determine the user's 'overallLevel' (1-10) and 'levelName'.
${JSON.stringify(LEVEL_DEFINITIONS, null, 2)}

Based on your analysis of the audio against the phonetic targets AND the level definitions provided, return a JSON object with this exact structure:
{
  "overallLevel": number (1-10),
  "levelName": "Tourist" | "Local" | "Insider",
  "phoneticProfile": {
    "flapT": { "score": 1-10, "feedback": "specific feedback", "priority": "high" | "medium" | "low" },
    "connectedSpeech": { "score": 1-10, "feedback": "...", "priority": "..." },
    "thSounds": { "score": 1-10, "feedback": "...", "priority": "..." },
    "vowelQuality": { "score": 1-10, "feedback": "...", "priority": "..." },
    "rhythmStress": { "score": 1-10, "feedback": "...", "priority": "..." }
  },
  "topStrength": "string describing their best area",
  "primaryFocus": "the ONE thing to work on first",
  "secondaryFocus": "the second priority",
  "recommendedPath": "CONNECTED_SPEECH" | "SOUND_ACCURACY" | "RHYTHM_FLOW" | "VOCABULARY_SLANG",
  "encouragement": "personalized motivational message"
}`;

  const phoneticCategorySchema = {
    type: Type.OBJECT,
    properties: {
        score: { type: Type.INTEGER },
        feedback: { type: Type.STRING },
        priority: { type: Type.STRING, enum: [Priority.HIGH, Priority.MEDIUM, Priority.LOW] },
    }
  };

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
        overallLevel: { type: Type.INTEGER },
        levelName: { type: Type.STRING, enum: [Level.TOURIST, Level.LOCAL, Level.INSIDER] },
        phoneticProfile: {
            type: Type.OBJECT,
            properties: {
                flapT: phoneticCategorySchema,
                connectedSpeech: phoneticCategorySchema,
                thSounds: phoneticCategorySchema,
                vowelQuality: phoneticCategorySchema,
                rhythmStress: phoneticCategorySchema,
            }
        },
        topStrength: { type: Type.STRING },
        primaryFocus: { type: Type.STRING },
        secondaryFocus: { type: Type.STRING },
        recommendedPath: { type: Type.STRING, enum: [LearningPath.CONNECTED_SPEECH, LearningPath.SOUND_ACCURACY, LearningPath.RHYTHM_FLOW, LearningPath.VOCABULARY_SLANG] },
        encouragement: { type: Type.STRING },
    }
  };

  const contents = {
      parts: [...audioParts, { text: prompt }],
  };

  try {
      const response: GenerateContentResponse = await ai.models.generateContent({
          model: 'gemini-3-pro-preview', // Use a more powerful model for this complex task
          contents,
          config: {
              systemInstruction,
              responseMimeType: 'application/json',
              responseSchema,
          }
      });
      const jsonText = response.text || '{}';
      return JSON.parse(jsonText) as AssessmentResult;
  } catch (error) {
      console.error("Error assessing user level:", error);
      // Fallback result in case of an error
      return {
          overallLevel: 3,
          levelName: Level.TOURIST,
          phoneticProfile: {
              flapT: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              connectedSpeech: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              thSounds: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              vowelQuality: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
              rhythmStress: { score: 3, feedback: "Error during analysis.", priority: Priority.HIGH },
          },
          topStrength: "Persistence!",
          primaryFocus: "Basic pronunciation.",
          secondaryFocus: "Speaking rhythm.",
          recommendedPath: LearningPath.SOUND_ACCURACY,
          encouragement: "We couldn't analyze your audio, but don't worry! Let's start with the fundamentals together.",
      };
  }
};

export const generateExercise = async (level: Level, module: PathModule): Promise<Exercise> => {
    const ai = getAi();
    const systemInstruction = "You are an expert curriculum designer for American English learners. Your tone is energetic and encouraging. You create specific, targeted exercises in a structured JSON format.";

    const prompt = `Generate a single, complete exercise object for a language learner at the '${level}' level.

The current learning module is "${module.name}".
The module's objectives are:
- ${module.objectives.join('\n- ')}

Your task is to create a JSON exercise object.
1.  First, you MUST choose one exercise type from this list of allowed types for this module: [${module.exercises.join(', ')}].
2.  Then, create the full exercise JSON object.
3.  The 'content.text' MUST be a very short, casual text (one or two natural sentences) that is specifically designed to help the user practice the module's objectives.
4.  Provide 1-2 concise and highly practical 'content.tips' for the user.
5.  Set the 'difficulty' to 1 for Tourist, 2 for Local, or 3 for Insider level.
6.  The response MUST be a single JSON object matching the provided schema.`;

    const responseSchema = {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: Object.values(ExerciseType) },
        content: {
          type: Type.OBJECT,
          properties: {
            audioUrl: { type: Type.STRING },
            text: { type: Type.STRING },
            breakdown: { type: Type.ARRAY, items: { type: Type.STRING } },
            tips: { type: Type.ARRAY, items: { type: Type.STRING } },
            modelPronunciation: { type: Type.STRING }
          }
        },
        targetSounds: { type: Type.ARRAY, items: { type: Type.STRING } },
        difficulty: { type: Type.INTEGER }
      }
    };

    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema
            },
        });
        const jsonText = response.text || '{}';
        return JSON.parse(jsonText) as Exercise;
    } catch (error) {
        console.error("Error generating exercise:", error);
        return {
            type: ExerciseType.LISTEN_REPEAT,
            content: {
                text: "Sorry, we couldn't create an exercise. Let's try this: 'What's up?'",
                tips: ["Try to make it sound friendly!"]
            },
            difficulty: 1
        };
    }
};

export const generateTTSAudio = async (text: string): Promise<string> => {
    const ai = getAi();
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Kore' }, // A friendly, clear voice
                    },
                },
            },
        });
        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data returned from TTS API");
        }
        return base64Audio;
    } catch (error) {
        console.error("Error generating TTS audio:", error);
        throw new Error("Failed to generate audio for the exercise.");
    }
};


