import PathComplete from './components/PathComplete';
import PracticeSession from './components/PracticeSession';
import { Spinner } from './components/ui/Spinner';

const App: React.FC = () => {
  const [phase, setPhase] = useState<AppPhase>(AppPhase.WELCOME);
  const [level, setLevel] = useState<Level | null>(null);
  const [goal, setGoal] = useState<Goal>(Goal.CASUAL);
  const [assessmentResult, setAssessmentResult] = useState<AssessmentResult | null>(null);

  // Diagnostic flow state
  const [assessmentIndex, setAssessmentIndex] = useState(0);
  const [diagnosticRecordings, setDiagnosticRecordings] = useState<Blob[]>([]);

  // Learning Path state
  const [currentLearningPath, setCurrentLearningPath] = useState<LearningPathDefinition | null>(null);
  const [currentModuleIndex, setCurrentModuleIndex] = useState(0);

  // Main practice loop state
  const [currentExercise, setCurrentExercise] = useState<Exercise | null>(null);

  const handleStart = useCallback((selectedGoal: Goal) => {
    setGoal(selectedGoal);
    setPhase(AppPhase.ASSESSMENT_RECORD);
  }, []);

  const handleSingleRecordingComplete = useCallback((recording: Blob) => {
    const newRecordings = [...diagnosticRecordings, recording];
    setDiagnosticRecordings(newRecordings);

    if (assessmentIndex < ASSESSMENT_TEXTS.length - 1) {
      setAssessmentIndex(prev => prev + 1);
    } else {
      setPhase(AppPhase.ASSESSMENT_ANALYZE);
    }
  }, [diagnosticRecordings, assessmentIndex]);

  useEffect(() => {
    const runAnalysis = async () => {
      if (phase === AppPhase.ASSESSMENT_ANALYZE && diagnosticRecordings.length === ASSESSMENT_TEXTS.length) {
        const finalAssessment = await assessUserLevel(diagnosticRecordings, goal, ASSESSMENT_TEXTS);
        setAssessmentResult(finalAssessment);
        setLevel(finalAssessment.levelName);
        setPhase(AppPhase.ASSESSMENT_RESULTS);
      }
    };
    runAnalysis();
  }, [phase, diagnosticRecordings, goal]);

  const handleStartPlan = useCallback(() => {
    if (assessmentResult) {
      const path = LEARNING_PATHS.find(p => p.path === assessmentResult.recommendedPath);
      if (path) {
        setCurrentLearningPath(path);
        setCurrentModuleIndex(0);
        setPhase(AppPhase.LEARNING_PATH_OVERVIEW);
      } else {
        setPhase(AppPhase.PRACTICE_SESSION_GENERATE);
      }
    }
  }, [assessmentResult]);

  const handleStartModule = useCallback(() => {
    setPhase(AppPhase.PRACTICE_SESSION_GENERATE);
  }, []);

  useEffect(() => {
    if (phase === AppPhase.PRACTICE_SESSION_GENERATE && level && currentLearningPath) {
        const fetchExercise = async () => {
            const module = currentLearningPath.modules[currentModuleIndex];
            const exercise = await generateExercise(level, module);
            setCurrentExercise(exercise);
            setPhase(AppPhase.PRACTICE_SESSION);
        };
        fetchExercise();
    }
  }, [phase, level, currentLearningPath, currentModuleIndex]);

  const handleSessionComplete = useCallback(() => {
    setCurrentExercise(null);
    if (currentLearningPath && currentModuleIndex < currentLearningPath.modules.length - 1) {
      setCurrentModuleIndex(prev => prev + 1);
      setPhase(AppPhase.PRACTICE_SESSION_GENERATE);
    } else {
      setPhase(AppPhase.PATH_COMPLETE);
    }
  }, [currentLearningPath, currentModuleIndex]);

  const handleRestart = useCallback(() => {
      window.location.reload();
  }, []);

  const renderContent = () => {
    switch (phase) {
      case AppPhase.WELCOME:
        return <Welcome onStart={handleStart} />;
      case AppPhase.ASSESSMENT_RECORD:
      case AppPhase.ASSESSMENT_ANALYZE:
        return (
          <Assessment 
            currentPhase={phase} 
            assessmentIndex={assessmentIndex}
            onSingleRecordingComplete={handleSingleRecordingComplete}
          />
        );
      case AppPhase.ASSESSMENT_RESULTS:
        return <AssessmentResults result={assessmentResult} onStartPlan={handleStartPlan} />;
      case AppPhase.LEARNING_PATH_OVERVIEW:
        if (!currentLearningPath) return null;
        return <LearningPathOverview learningPath={currentLearningPath} onStartModule={handleStartModule} />;
      case AppPhase.PATH_COMPLETE:
        return <PathComplete onRestart={handleRestart} />;
      case AppPhase.PRACTICE_SESSION_GENERATE:
         return (
            <div className="flex flex-col items-center justify-center text-center">
                <Spinner />
                <p className="mt-4 text-gray-400">Designing the perfect exercise for you...</p>
            </div>
         );
      case AppPhase.PRACTICE_SESSION:
        if (!currentExercise || !level || !currentLearningPath) return null;
         return (
            <PracticeSession
                level={level}
                exercise={currentExercise}
                module={currentLearningPath.modules[currentModuleIndex]}
                moduleNumber={currentModuleIndex + 1}
                onSessionComplete={handleSessionComplete}
            />
         );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center justify-center p-4 selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-indigo-400 tracking-tight">
            The American Cultural Insider
          </h1>
          <p className="text-gray-400 mt-2">Your coach for sounding like a local 🤙</p>
        </header>
        <main className="bg-gray-800 rounded-2xl shadow-2xl p-6 md:p-8 min-h-[400px] flex flex-col justify-center">
          {renderContent()}
        </main>
        <footer className="text-center mt-8 text-gray-500 text-sm">
          <p>Powered by Gemini. Built for a natural, authentic learning experience.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Exercise, PathModule, DetailedFeedback, VibeCheckContent, SpokenResponseAnalysis, Level } from '../types';
import { generateTTSAudio, analyzeAudioDetailed, generateVibeCheck, analyzeSpokenResponse } from '../services/geminiService';
import { playPcmAudio } from '../utils/audio';
import { Button } from './ui/Button';
import { Spinner } from './ui/Spinner';
import { Recorder } from './ui/Recorder';
import { ScoreBar } from './ui/ScoreBar';

enum PracticeStep {
  NOTICING,
  MODELING,
  SHADOWING,
  PRODUCTION_RECORD,
  PRODUCTION_REVIEW,
  INTEGRATION_CHALLENGE,
  INTEGRATION_REVIEW,
}

const stepInfo = {
    [PracticeStep.NOTICING]: { number: 1, name: 'Noticing' },
    [PracticeStep.MODELING]: { number: 2, name: 'Modeling' },
    [PracticeStep.SHADOWING]: { number: 3, name: 'Shadowing' },
    [PracticeStep.PRODUCTION_RECORD]: { number: 4, name: 'Production' },
    [PracticeStep.PRODUCTION_REVIEW]: { number: 4, name: 'Production Feedback' },
    [PracticeStep.INTEGRATION_CHALLENGE]: { number: 5, name: 'Integration' },
    [PracticeStep.INTEGRATION_REVIEW]: { number: 5, name: 'Integration Feedback' },
}

interface PracticeSessionProps {
  exercise: Exercise;
  level: Level;
  module: PathModule;
  moduleNumber: number;
  onSessionComplete: () => void;
}

const PlayIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" viewBox="0 0 20 20" fill="currentColor"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" /></svg>;

const PracticeSession: React.FC<PracticeSessionProps> = ({ exercise, level, module, moduleNumber, onSessionComplete }) => {
    const [step, setStep] = useState<PracticeStep>(PracticeStep.NOTICING);
    const [modelAudio, setModelAudio] = useState<string | null>(null);
    const [isLoadingAudio, setIsLoadingAudio] = useState(true);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [productionAnalysis, setProductionAnalysis] = useState<DetailedFeedback | null>(null);
    const [vibeCheck, setVibeCheck] = useState<VibeCheckContent | null>(null);
    const [integrationAnalysis, setIntegrationAnalysis] = useState<SpokenResponseAnalysis | null>(null);
    const audioContextRef = useRef<AudioContext | null>(null);

    useEffect(() => {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        const getAudio = async () => {
            try {
                const audio = await generateTTSAudio(exercise.content.text);
                setModelAudio(audio);
            } catch (error) {
                console.error("Failed to load model audio", error);
            } finally {
                setIsLoadingAudio(false);
            }
        };
        getAudio();

        return () => {
            audioContextRef.current?.close();
        }
    }, [exercise.content.text]);

    const handlePlayModelAudio = () => {
        if (modelAudio && audioContextRef.current) {
            playPcmAudio(modelAudio, audioContextRef.current);
        }
    };

    const handleProductionRecording = useCallback(async (blob: Blob) => {
        setIsAnalyzing(true);
        const analysis = await analyzeAudioDetailed(exercise.content.text, blob, module.objectives, level);
        setProductionAnalysis(analysis);
        setIsAnalyzing(false);
        setStep(PracticeStep.PRODUCTION_REVIEW);
    }, [exercise.content.text, module.objectives, level]);

    const handleIntegrationRecording = useCallback(async (blob: Blob) => {
        if (!vibeCheck?.challenge) return;
        setIsAnalyzing(true);
        const analysis = await analyzeSpokenResponse(vibeCheck.challenge, blob);
        setIntegrationAnalysis(analysis);
        setIsAnalyzing(false);
        setStep(PracticeStep.INTEGRATION_REVIEW);
    }, [vibeCheck?.challenge]);

    useEffect(() => {
        if(step === PracticeStep.INTEGRATION_CHALLENGE && !vibeCheck) {
            const getVibeCheck = async () => {
                const content = await generateVibeCheck(exercise.content.text);
                setVibeCheck(content);
            };
            getVibeCheck();
        }
    }, [step, vibeCheck, exercise.content.text]);

    const renderContent = () => {
        if (isLoadingAudio && step < PracticeStep.PRODUCTION_RECORD) {
            return <div className="text-center"><Spinner /><p className="mt-4">Warming up the AI coach...</p></div>;
        }

        switch (step) {
            case PracticeStep.NOTICING:
            case PracticeStep.MODELING:
            case PracticeStep.SHADOWING:
                const titles = {
                    [PracticeStep.NOTICING]: "Listen Closely",
                    [PracticeStep.MODELING]: "Hear the Model",
                    [PracticeStep.SHADOWING]: "Shadow the Speaker",
                };
                const descriptions = {
                    [PracticeStep.NOTICING]: "First, just listen to the model pronunciation. Notice the rhythm and any linked sounds.",
                    [PracticeStep.MODELING]: "Listen again. Pay close attention to how the coach's tips are applied in the speech.",
                    [PracticeStep.SHADOWING]: "Now, try to speak along with the recording. Don't worry about perfection, just match the timing and flow.",
                };
                return (
                    <div className="text-center space-y-6">
                        <h3 className="text-xl font-bold text-white">{titles[step]}</h3>
                        <p className="text-lg text-gray-200 bg-gray-700/50 p-4 rounded-lg">{exercise.content.text}</p>
                        <Button onClick={handlePlayModelAudio}><PlayIcon /> Play Model Audio</Button>
                        <p className="text-gray-400">{descriptions[step]}</p>
                    </div>
                );

            case PracticeStep.PRODUCTION_RECORD:
                return (
                    <div className="text-center space-y-6">
                        <h3 className="text-xl font-bold text-white">Your Turn to Speak</h3>
                        <p className="text-lg text-gray-200 bg-gray-700/50 p-4 rounded-lg">{exercise.content.text}</p>
                        <p className="text-gray-400">Record yourself saying the sentence. Take your time and apply what you've noticed.</p>
                        <Recorder onRecordingComplete={handleProductionRecording} />
                    </div>
                );

            case PracticeStep.PRODUCTION_REVIEW:
                if (isAnalyzing) return <div className="text-center"><Spinner /><p className="mt-4">Analyzing your production...</p></div>;
                if (!productionAnalysis) return <p className="text-red-400">Could not get analysis.</p>;
                return (
                    <div className="space-y-4 text-left w-full max-h-[500px] overflow-y-auto pr-2">
                        <div className="text-center mb-4">
                            <p className="text-gray-400">Overall Score</p>
                            <p className="text-4xl font-bold text-indigo-400">{productionAnalysis.overallScore * 10}<span className="text-2xl text-gray-500">/100</span></p>
                        </div>

                        <div className="p-3 bg-green-900/40 border border-green-500/50 rounded-lg">
                           <h4 className="font-bold text-green-300">👍 What you did well!</h4>
                           <p className="text-gray-300 text-sm">{productionAnalysis.celebration}</p>
                        </div>

                        <div className="p-3 bg-yellow-900/40 border border-yellow-500/50 rounded-lg">
                           <h4 className="font-bold text-yellow-300">🎯 Your #1 Focus</h4>
                           <p className="text-gray-300 text-sm">{productionAnalysis.oneThingToFix}</p>
                        </div>

                        <div className="p-3 bg-gray-700/50 rounded-lg">
                            <h4 className="font-bold text-indigo-300 mb-2">Detailed Analysis</h4>
                             {productionAnalysis.targetFeaturesAnalysis.map((feat, i) => (
                                <div key={i} className="mb-3 last:mb-0 border-b border-gray-600 pb-2">
                                    <div className="flex justify-between items-center">
                                        <p className="font-semibold text-white">{feat.feature}</p>
                                        <p className="font-bold text-indigo-300">{feat.score * 10}</p>
                                    </div>
                                    <p className="text-xs text-gray-400 italic bg-gray-800 p-2 rounded mt-1">
                                      <span className="font-semibold text-gray-300">How it looks:</span> "{feat.howItLooks}" → <span className="font-semibold text-gray-300">How it sounds:</span> "{feat.howItSounds}"
                                    </p>
                                    <p className="text-xs text-gray-300 mt-1"><strong className="text-blue-300">Tip:</strong> {feat.tip}</p>
                                </div>
                             ))}
                             <div className="grid grid-cols-3 gap-2 text-center mt-4">
                                <div>
                                    <p className="text-sm text-gray-400">Rhythm</p>
                                    <ScoreBar score={productionAnalysis.rhythm.score * 10} />
                                </div>
                                <div>
                                    <p className="text-sm text-gray-400">Clarity</p>
                                    <ScoreBar score={productionAnalysis.clarity.score * 10} />
                                </div>
                                <div>
                                    <p className="text-sm text-gray-400">Naturalness</p>
                                    <ScoreBar score={productionAnalysis.naturalness.score * 10} />
                                </div>
                             </div>
                        </div>

                         <div className="p-3 bg-blue-900/40 border border-blue-500/50 rounded-lg">
                           <h4 className="font-bold text-blue-300">💡 Coach's Recommendation</h4>
                           <p className="text-gray-300 text-sm">{productionAnalysis.practiceRecommendation}</p>
                        </div>
                    </div>
                );

            case PracticeStep.INTEGRATION_CHALLENGE:
                 if (!vibeCheck) return <div className="text-center"><Spinner /><p className="mt-4">Generating your challenge...</p></div>;
                 return (
                    <div className="text-center space-y-6">
                        <h3 className="text-xl font-bold text-white">Integrate Your Skill</h3>
                         <div className="p-4 bg-blue-900/40 border border-blue-500/50 rounded-lg">
                            <p className="text-gray-200">{vibeCheck.challenge}</p>
                        </div>
                        <Recorder onRecordingComplete={handleIntegrationRecording} />
                    </div>
                );

            case PracticeStep.INTEGRATION_REVIEW:
                if (isAnalyzing) return <div className="text-center"><Spinner /><p className="mt-4">Analyzing your response...</p></div>;
                if (!integrationAnalysis) return <p className="text-red-400">Could not get analysis.</p>;
                return (
                     <div className="text-center space-y-4">
                        <h3 className="text-xl font-bold text-white">Integration Feedback</h3>
                         <div className="p-4 bg-gray-700/50 rounded-lg">
                           <h4 className="font-bold text-indigo-300 mb-2">Coach's Comments <span className="text-sm font-normal text-gray-400">(Score: {integrationAnalysis.score}/100)</span></h4>
                           <p className="text-gray-300 italic">"{integrationAnalysis.feedback}"</p>
                        </div>
                    </div>
                );
        }
    };

    const currentStepInfo = stepInfo[step];

    return (
        <div className="flex flex-col animate-fade-in space-y-6 w-full">
            <header className="text-center">
                 <h2 className="text-lg font-bold text-indigo-400">Module {moduleNumber}: {module.name}</h2>
                 <p className="text-sm text-gray-400">Step {currentStepInfo.number}/5: {currentStepInfo.name}</p>
            </header>

            <div className="p-4 bg-gray-900/50 rounded-lg min-h-[200px] flex items-center justify-center">
                {renderContent()}
            </div>

            <div className="flex justify-center">
                {step < PracticeStep.INTEGRATION_REVIEW && <Button onClick={() => setStep(s => s + 1)}>Next Step</Button>}
                {step === PracticeStep.INTEGRATION_REVIEW && <Button onClick={onSessionComplete}>Finish Session</Button>}
            </div>
        </div>
    );
};

export default PracticeSession;

