// Create new file: store/userProgress.ts
// Using localStorage for persistence (or integrate with a backend later)

export interface UserProgress {
  odId: string;                       // User identifier
  createdAt: string;
  lastSessionAt: string;

  // Assessment data
  initialAssessment: DetailedAssessmentResult | null;
  assessmentHistory: AssessmentHistoryEntry[];

  // Level & path
  currentLevel: number;               // 1-10
  currentLevelName: Level;
  assignedPath: LearningPath;

  // Module progress
  completedModules: string[];         // Module IDs
  currentModule: string | null;
  moduleProgress: Record<string, ModuleProgress>;

  // Exercise performance
  exerciseHistory: ExerciseAttempt[];

  // Phonetic profile (updated after each assessment)
  phoneticProfile: PhoneticProfile;

  // Stats
  totalPracticeMinutes: number;
  totalSessions: number;
  streakDays: number;
  lastStreakDate: string;
}

export interface AssessmentHistoryEntry {
  date: string;
  level: number;
  phoneticProfile: PhoneticProfile;
}

export interface ModuleProgress {
  moduleId: string;
  started: string;
  completed: string | null;
  exercisesCompleted: number;
  exercisesTotal: number;
  averageScore: number;
}

export interface ExerciseAttempt {
  exerciseId: string;
  moduleId: string;
  date: string;
  score: number;
  feedback: string;
  targetFeatures: string[];
  duration: number;
}

export interface PhoneticProfile {
  flapT: FeatureScore;
  connectedSpeech: FeatureScore;
  thSounds: FeatureScore;
  vowelQuality: FeatureScore;
  rhythmStress: FeatureScore;
  rSound: FeatureScore;
  intonation: FeatureScore;
}

export interface FeatureScore {
  score: number;
  trend: 'improving' | 'stable' | 'needs_work';
  lastUpdated: string;
  history: number[];  // Last 10 scores
}

// Storage functions
export const saveProgress = (progress: UserProgress): void => {
  localStorage.setItem('accent_app_progress', JSON.stringify(progress));
};

export const loadProgress = (): UserProgress | null => {
  const data = localStorage.getItem('accent_app_progress');
  return data ? JSON.parse(data) : null;
};

export const initializeProgress = (assessment: DetailedAssessmentResult): UserProgress => {
  return {
    odId: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
    lastSessionAt: new Date().toISOString(),
    initialAssessment: assessment,
    assessmentHistory: [{
      date: new Date().toISOString(),
      level: assessment.overallLevel,
      phoneticProfile: assessment.phoneticProfile
    }],
    currentLevel: assessment.overallLevel,
    currentLevelName: assessment.levelName,
    assignedPath: assessment.recommendedPath,
    completedModules: [],
    currentModule: null,
    moduleProgress: {},
    exerciseHistory: [],
    phoneticProfile: assessment.phoneticProfile,
    totalPracticeMinutes: 0,
    totalSessions: 1,
    streakDays: 1,
    lastStreakDate: new Date().toISOString().split('T')[0]
  };
};

