// FIX: Define Level enum to break circular dependency with data/levels.ts
export enum Level {
  TOURIST = 'Tourist',
  LOCAL = 'Local',
  INSIDER = 'Insider',
}

export enum AppPhase {
  WELCOME = 'WELCOME',
  ASSESSMENT_RECORD = 'ASSESSMENT_RECORD',
  ASSESSMENT_ANALYZE = 'ASSESSMENT_ANALYZE',
  ASSESSMENT_RESULTS = 'ASSESSMENT_RESULTS',
  LEARNING_PATH_OVERVIEW = 'LEARNING_PATH_OVERVIEW',
  PATH_COMPLETE = 'PATH_COMPLETE',
  PRACTICE_SESSION_GENERATE = 'PRACTICE_SESSION_GENERATE',
  PRACTICE_SESSION = 'PRACTICE_SESSION',
  // FIX: Add legacy phases to fix compilation errors in unused components.
  PHASE_1_GENERATE = 'PHASE_1_GENERATE',
  PHASE_2_ANALYZE = 'PHASE_2_ANALYZE',
  PHASE_3_GENERATE = 'PHASE_3_GENERATE',
}

export enum Goal {
  CASUAL = 'Natural & Clear',
  SLANG = 'Fluent with Slang',
}

export interface SlangTerm {
  term: string;
  meaning: string;
}

export interface VibeCheckContent {
  slangBreakdown: SlangTerm[];
  questions: string[];
  challenge: string;
}

export enum Priority {
  HIGH = 'high',
  MEDIUM = 'medium',
  LOW = 'low',
}

export enum LearningPath {
    CONNECTED_SPEECH = 'CONNECTED_SPEECH',
    SOUND_ACCURACY = 'SOUND_ACCURACY',
    RHYTHM_FLOW = 'RHYTHM_FLOW',
    VOCABULARY_SLANG = 'VOCABULARY_SLANG'
}

export interface PhoneticCategoryAnalysis {
    score: number; // 1-10
    feedback: string;
    priority: Priority;
}

export interface PhoneticProfile {
    flapT: PhoneticCategoryAnalysis;
    connectedSpeech: PhoneticCategoryAnalysis;
    thSounds: PhoneticCategoryAnalysis;
    vowelQuality: PhoneticCategoryAnalysis;
    rhythmStress: PhoneticCategoryAnalysis;
    rSound: PhoneticCategoryAnalysis;
    intonation: PhoneticCategoryAnalysis;
}

export interface AssessmentResult {
    overallLevel: number; // 1-10
    levelName: Level;
    phoneticProfile: PhoneticProfile;
    topStrength: string;
    primaryFocus: string;
    secondaryFocus: string;
    recommendedPath: LearningPath;
    encouragement: string;
}

export interface DetailedAudioAnalysis {
  isCorrect: boolean;
  incorrectPhrase: string | null;
  feedback: string;
  phoneticExplanation: string;
  score: number;
}

export interface SpokenResponseAnalysis {
    feedback: string;
    score: number;
}

export interface PhoneticTarget {
  sound: string;           // IPA notation
  examples: string[];      // words in the text
  commonErrors: string[];  // what non-natives typically do wrong
}

export interface AssessmentText {
  id: string;
  text: string;
  targets: PhoneticTarget[];
  difficulty: 'diagnostic';
}

export enum ExerciseType {
  // Shadowing variants
  SHADOWING = 'SHADOWING',           // Standard: speak along
  DELAYED_SHADOWING = 'DELAYED_SHADOWING', // Speak 1-2 seconds behind
  MUMBLE_SHADOWING = 'MUMBLE_SHADOWING',   // Focus on rhythm, not words

  // Sound-focused
  MINIMAL_PAIRS = 'MINIMAL_PAIRS',   // bit/beat, ship/sheep
  TONGUE_PLACEMENT = 'TONGUE_PLACEMENT', // Physical instruction
  MIRROR_PRACTICE = 'MIRROR_PRACTICE',   // Visual feedback
  // FIX: Added missing ExerciseType enum members to fix errors in data/learningPaths.ts.
  TONGUE_TWISTERS = 'TONGUE_TWISTERS',
  WORD_LISTS = 'WORD_LISTS',
  VOWEL_CHARTS = 'VOWEL_CHARTS',

  // Comprehension
  LISTEN_REPEAT = 'LISTEN_REPEAT',   // Listen, then repeat
  LISTEN_IDENTIFY = 'LISTEN_IDENTIFY', // Identify what you hear
  DICTATION = 'DICTATION',           // Write what you hear

  // Production
  FREESTYLE = 'FREESTYLE',           // Free practice with target
  TRANSLATION = 'TRANSLATION',       // Formal → casual
  SENTENCE_BUILD = 'SENTENCE_BUILD', // Build up complexity
  ROLE_PLAY = 'ROLE_PLAY',          // Situational practice
  CONTEXT_MATCHING = 'CONTEXT_MATCHING',
  DIALOGUE_PRACTICE = 'DIALOGUE_PRACTICE',
  REPLACE_FORMAL = 'REPLACE_FORMAL',
  NATURAL_INSERTION = 'NATURAL_INSERTION',
  REFERENCE_MATCHING = 'REFERENCE_MATCHING',

  // Rhythm
  BEAT_MAPPING = 'BEAT_MAPPING',     // Map stress patterns
  METRONOME_PRACTICE = 'METRONOME_PRACTICE', // Practice to a beat
  SCHWA_SPOTTING = 'SCHWA_SPOTTING',
  INTONATION_MAPPING = 'INTONATION_MAPPING',
  FOCUS_DRILLS = 'FOCUS_DRILLS',

  // Integrated
  CONVERSATION = 'CONVERSATION',     // AI conversation partner
  SPEED_DRILLS = 'SPEED_DRILLS'     // Gradually increase speed
}

export interface ExerciseContent {
  audioUrl?: string;        // For listening exercises
  text: string;             // Main text
  breakdown?: string[];     // Chunked version
  tips?: string[];          // Pronunciation tips
  modelPronunciation?: string; // IPA
}

export interface Exercise {
  type: ExerciseType;
  content: ExerciseContent;
  targetSounds?: string[];
  difficulty: 1 | 2 | 3;
