  // Stats
  totalPracticeMinutes: number;
  totalSessions: number;
  streakDays: number;
  lastStreakDate: string;
}

// Storage functions
export const saveProgress = (progress: UserProgress): void => {
  try {
    localStorage.setItem('accent_app_progress', JSON.stringify(progress));
  } catch (error) {
    console.error("Could not save progress to localStorage", error);
  }
};

export const loadProgress = (): UserProgress | null => {
  try {
    const data = localStorage.getItem('accent_app_progress');
    return data ? JSON.parse(data) : null;
  } catch (error) {
    console.error("Could not load progress from localStorage", error);
    return null;
  }
};

export const initializeProgress = (assessment: AssessmentResult): UserProgress => {
  const now = new Date().toISOString();

  const transformProfile = (profile: AssessmentPhoneticProfile): PhoneticProfile => {
    const newProfile: Partial<PhoneticProfile> = {};
    for (const key in profile) {
      if (Object.prototype.hasOwnProperty.call(profile, key)) {
        const typedKey = key as keyof AssessmentPhoneticProfile;
        const analysis: PhoneticCategoryAnalysis = profile[typedKey];
        newProfile[typedKey] = {
          score: analysis.score,
          trend: 'stable',
          lastUpdated: now,
          history: [analysis.score],
        };
      }
    }
    return newProfile as PhoneticProfile;
  };

  return {
    odId: crypto.randomUUID(),
    createdAt: now,
    lastSessionAt: now,
    initialAssessment: assessment,
    assessmentHistory: [{
      date: now,
      level: assessment.overallLevel,
      phoneticProfile: assessment.phoneticProfile
    }],
    currentLevel: assessment.overallLevel,
    currentLevelName: assessment.levelName,
    assignedPath: assessment.recommendedPath,
    completedModules: [],
    currentModule: null,
    moduleProgress: {},
    exerciseHistory: [],
    phoneticProfile: transformProfile(assessment.phoneticProfile),
    totalPracticeMinutes: 0,
    totalSessions: 1,
    streakDays: 1,
    lastStreakDate: now.split('T')[0]
  };
};

