// Enhanced generateSocialScript
const getWeakAreas = (profile: UserProgressPhoneticProfile): string[] => {
    const weakAreas: { name: string, score: number }[] = [];
    const threshold = 7; // Defines a "weak area"

    (Object.keys(profile) as Array<keyof UserProgressPhoneticProfile>).forEach(key => {
      if (profile[key].score < threshold) {
        // A bit of formatting for the prompt
        const name = key.replace(/([A-Z])/g, ' $1').replace(/^./, (str) => str.toUpperCase());
        weakAreas.push({ name, score: profile[key].score });
      }
    });

    // Sort by lowest score to prioritize the weakest areas first
    weakAreas.sort((a, b) => a.score - b.score);

    return weakAreas.map(area => area.name).slice(0, 3); // Return top 3 weakest areas
};

export const generateTargetedScript = async (
  userProgress: UserProgress,
  currentModule: PathModule,
  difficulty: 1 | 2 | 3
): Promise<TargetedScript> => {
  const ai = getAi();

  const targetFeatures = currentModule.objectives.join(', ');
  const weakAreas = getWeakAreas(userProgress.phoneticProfile);

  const systemInstruction = `You are 'The American Cultural Insider', an expert curriculum designer creating hyper-personalized practice scripts for language learners.

CRITICAL REQUIREMENTS:
1. Scripts MUST contain the target features for the current module naturally. They should not feel forced or like a list of examples.
2. The script's difficulty must match the requested level (${difficulty}/3):
  - 1 (Easy): Short, simple sentences. Common vocabulary. Clear pauses.
  - 2 (Medium): More complex sentences, some idioms or phrasal verbs, natural pace.
  - 3 (Hard): Longer text, natural conversational complexity, includes slang and reductions.
3. The content MUST feel authentic to modern American culture. Think real conversations, social media posts, snippets of stories, etc.
4. The script text itself should NOT contain any emojis.
5. You must also weave in opportunities for the user to practice their specific weak areas: ${weakAreas.join(', ')}.`;

  const prompt = `Generate a targeted practice script.

- Module Objectives (Primary Focus): ${targetFeatures}
- User's Weak Areas (Secondary Focus): ${weakAreas.join(', ')}
- Difficulty: ${difficulty}/3

Return a single JSON object that strictly adheres to the provided schema.`;

    const targetInstanceSchema = {
        type: Type.OBJECT,
        properties: {
            phrase: { type: Type.STRING },
            feature: { type: Type.STRING },
            howItLooks: { type: Type.STRING },
            howItSounds: { type: Type.STRING, description: "Natural pronunciation with IPA, e.g., 'gonna [ɡʌnə]'" },
        },
        required: ['phrase', 'feature', 'howItLooks', 'howItSounds'],
    };

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            script: { type: Type.STRING, description: "The practice text, between 50 and 100 words." },
            type: { type: Type.STRING, enum: ["dialogue", "monologue", "social_post", "story"] },
            context: { type: Type.STRING, description: "A brief (1-2 sentence) context for the script." },
            targetInstances: { type: Type.ARRAY, items: targetInstanceSchema },
            warmupPhrase: { type: Type.STRING, description: "A single, short phrase from the script to warm up with." },
            pronunciation_notes: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ['script', 'type', 'context', 'targetInstances', 'warmupPhrase', 'pronunciation_notes'],
    };

  const contents = { parts: [{ text: prompt }] };

  try {
      const response: GenerateContentResponse = await ai.models.generateContent({
          model: 'gemini-3-pro-preview', // A complex generation task needs a powerful model
          contents,
          config: {
              systemInstruction,
              responseMimeType: 'application/json',
              responseSchema,
          }
      });
      const jsonText = response.text || '{}';
      return JSON.parse(jsonText) as TargetedScript;
  } catch (error) {
      console.error("Error generating targeted script:", error);
      return {
          script: "I couldn't generate a script right now. Let's try this: 'What are you going to do today?' It's a great phrase for practicing connected speech.",
          type: "monologue",
          context: "A simple question to practice.",
          targetInstances: [{
              phrase: "What are you going to do",
              feature: "Connected Speech",
              howItLooks: "What are you going to do",
              howItSounds: "Whaddya gonna do [wʌɾəjə ɡʌnə du]"
          }],
          warmupPhrase: "gonna do",
          pronunciation_notes: ["Try to link the words together smoothly."]
      };
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { AppPhase, Level, Goal, AssessmentResult, LearningPathDefinition, Exercise } from './types';
import { UserProgress } from './store/userProgress';
import { ASSESSMENT_TEXTS } from './data/assessmentTexts';
import { LEARNING_PATHS } from './data/learningPaths';
import { assessUserLevel, generateExercise } from './services/geminiService';
import { loadProgress, saveProgress, initializeProgress } from './store/userProgress';
import Welcome from './components/Welcome';
import Assessment from './components/Assessment';
import AssessmentResults from './components/AssessmentResults';
import Dashboard from './components/Dashboard';
import PathComplete from './components/PathComplete';
import PracticeSession from './components/PracticeSession';
import { Spinner } from './components/ui/Spinner';

const App: React.FC = () => {
  const [phase, setPhase] = useState<AppPhase | null>(null);
  const [goal, setGoal] = useState<Goal>(Goal.CASUAL);
  const [assessmentResult, setAssessmentResult] = useState<AssessmentResult | null>(null);
  const [userProgress, setUserProgress] = useState<UserProgress | null>(null);

  // Diagnostic flow state
  const [assessmentIndex, setAssessmentIndex] = useState(0);
  const [diagnosticRecordings, setDiagnosticRecordings] = useState<Blob[]>([]);

  // Learning Path state
  const [currentLearningPath, setCurrentLearningPath] = useState<LearningPathDefinition | null>(null);
  const [currentModuleIndex, setCurrentModuleIndex] = useState(0);

  // Main practice loop state
  const [currentExercise, setCurrentExercise] = useState<Exercise | null>(null);

  useEffect(() => {
    const loadedProgress = loadProgress();
    if (loadedProgress) {
        setUserProgress(loadedProgress);
        setGoal(loadedProgress.goal);
        const path = LEARNING_PATHS.find(p => p.path === loadedProgress.assignedPath);
        if (path) {
            setCurrentLearningPath(path);
            const lastCompletedModuleId = loadedProgress.completedModules[loadedProgress.completedModules.length - 1];
            const lastCompletedIndex = lastCompletedModuleId ? path.modules.findIndex(m => m.id === lastCompletedModuleId) : -1;
            setCurrentModuleIndex(lastCompletedIndex + 1);
        }
        setPhase(AppPhase.DASHBOARD);
    } else {
        setPhase(AppPhase.WELCOME);
    }
  }, []);

  const handleStart = useCallback((selectedGoal: Goal) => {
    setGoal(selectedGoal);
    setPhase(AppPhase.ASSESSMENT_RECORD);
  }, []);

  const handleSingleRecordingComplete = useCallback((recording: Blob) => {
    const newRecordings = [...diagnosticRecordings, recording];
    setDiagnosticRecordings(newRecordings);

    if (assessmentIndex < ASSESSMENT_TEXTS.length - 1) {
      setAssessmentIndex(prev => prev + 1);
    } else {
      setPhase(AppPhase.ASSESSMENT_ANALYZE);
    }
  }, [diagnosticRecordings, assessmentIndex]);

  useEffect(() => {
    const runAnalysis = async () => {
      if (phase === AppPhase.ASSESSMENT_ANALYZE && diagnosticRecordings.length === ASSESSMENT_TEXTS.length) {
        const finalAssessment = await assessUserLevel(diagnosticRecordings, goal, ASSESSMENT_TEXTS);
        setAssessmentResult(finalAssessment);
        setPhase(AppPhase.ASSESSMENT_RESULTS);
      }
    };
    runAnalysis();
  }, [phase, diagnosticRecordings, goal]);

  const handleStartPlan = useCallback(() => {
    if (assessmentResult) {
      const path = LEARNING_PATHS.find(p => p.path === assessmentResult.recommendedPath);
      if (path) {
        const progress = initializeProgress(assessmentResult);
        progress.currentModule = path.modules[0].id; // Set the first module as current

        saveProgress(progress);
        setUserProgress(progress);
        setCurrentLearningPath(path);
        setCurrentModuleIndex(0);
        setPhase(AppPhase.DASHBOARD);
      }
    }
  }, [assessmentResult]);

  const handleStartSession = useCallback(() => {
    setPhase(AppPhase.PRACTICE_SESSION_GENERATE);
  }, []);

  useEffect(() => {
    if (phase === AppPhase.PRACTICE_SESSION_GENERATE && userProgress && currentLearningPath) {
        const fetchExercise = async () => {
            const module = currentLearningPath.modules[currentModuleIndex];
            const exercise = await generateExercise(userProgress.currentLevelName, module);
            setCurrentExercise(exercise);
            setPhase(AppPhase.PRACTICE_SESSION);
        };
        fetchExercise();
    }
  }, [phase, userProgress, currentLearningPath, currentModuleIndex]);

  const handleSessionComplete = useCallback(() => {
    if (!userProgress || !currentLearningPath) return;

    const completedModuleId = currentLearningPath.modules[currentModuleIndex].id;
    const newCompletedModules = [...userProgress.completedModules, completedModuleId];
    const newModuleIndex = currentModuleIndex + 1;

    setCurrentExercise(null);

    if (newModuleIndex < currentLearningPath.modules.length) {
      const newCurrentModuleId = currentLearningPath.modules[newModuleIndex].id;
      const updatedProgress = {
        ...userProgress,
        completedModules: newCompletedModules,
        currentModule: newCurrentModuleId,
        lastSessionAt: new Date().toISOString(),
        totalSessions: userProgress.totalSessions + 1,
      };

      setUserProgress(updatedProgress);
      saveProgress(updatedProgress);
      setCurrentModuleIndex(newModuleIndex);
      setPhase(AppPhase.DASHBOARD);
    } else {
      const updatedProgress = {
        ...userProgress,
        completedModules: newCompletedModules,
        currentModule: null, // No current module
      };
      setUserProgress(updatedProgress);
      saveProgress(updatedProgress);
      setPhase(AppPhase.PATH_COMPLETE);
    }
  }, [userProgress, currentLearningPath, currentModuleIndex]);

  const handleRestart = useCallback(() => {
      localStorage.removeItem('accent_app_progress');
      window.location.reload();
  }, []);

  const renderContent = () => {
    if (phase === null) {
      return (
        <div className="flex items-center justify-center">
          <Spinner />
        </div>
      );
    }
    switch (phase) {
      case AppPhase.WELCOME:
        return <Welcome onStart={handleStart} />;
      case AppPhase.ASSESSMENT_RECORD:
      case AppPhase.ASSESSMENT_ANALYZE:
        return (
          <Assessment 
            currentPhase={phase} 
            assessmentIndex={assessmentIndex}
            onSingleRecordingComplete={handleSingleRecordingComplete}
          />
        );
      case AppPhase.ASSESSMENT_RESULTS:
        return <AssessmentResults result={assessmentResult} onStartPlan={handleStartPlan} />;
      case AppPhase.DASHBOARD:
        if (!userProgress || !currentLearningPath) return null;
        return <Dashboard 
          userProgress={userProgress} 
          learningPath={currentLearningPath}
          currentModuleIndex={currentModuleIndex}
          onStartSession={handleStartSession} 
        />;
      case AppPhase.PATH_COMPLETE:
        return <PathComplete onRestart={handleRestart} />;
      case AppPhase.PRACTICE_SESSION_GENERATE:
         return (
            <div className="flex flex-col items-center justify-center text-center">
                <Spinner />
                <p className="mt-4 text-gray-400">Designing the perfect exercise for you...</p>
            </div>
         );
      case AppPhase.PRACTICE_SESSION:
        if (!currentExercise || !userProgress || !currentLearningPath) return null;
         return (
            <PracticeSession
                level={userProgress.currentLevelName}
                exercise={currentExercise}
                module={currentLearningPath.modules[currentModuleIndex]}
                moduleNumber={currentModuleIndex + 1}
                onSessionComplete={handleSessionComplete}
            />
         );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 flex flex-col items-center justify-center p-4 selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-indigo-400 tracking-tight">
            The American Cultural Insider
          </h1>
          <p className="text-gray-400 mt-2">Your coach for sounding like a local 🤙</p>
        </header>
        <main className="bg-gray-800 rounded-2xl shadow-2xl p-6 md:p-8 min-h-[400px] flex flex-col justify-center">
          {renderContent()}
        </main>
        <footer className="text-center mt-8 text-gray-500 text-sm">
          <p>Powered by Gemini. Built for a natural, authentic learning experience.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

